bs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45552\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"http://ma.tt/2015/11/mario-and-nux/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:734:\"<p><span class=\"embed-youtube\"></span></p>\n<p>In this video Shigeru Miyamoto and Takashi Tezuka discuss World 1-1, or the very first level in the very first Super Mario Bros. It&#8217;s fascinating how every element on the level is designed to introduce you to a mechanic of the game, or how Mario moves and jumps. This is interesting if you like Mario, but also important for any developer in any medium who is thinking about the NUX (new user experience) of their product. I sometimes joke that in <a href=\"http://wordpress.org/\">WordPress</a> we put people on the boss monster level the first time they enter the dashboard. There have been improvements but still so much to do to naturally introduce people to our interface.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 02 Nov 2015 15:26:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Fixing DST\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45543\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"http://ma.tt/2015/11/fixing-dst/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:230:\"<p>The Atlantic: <a href=\"http://www.theatlantic.com/business/archive/2013/11/daylight-saving-time-is-terrible-heres-a-simple-plan-to-fix-it/281075/\">Daylight Saving Time Is Terrible: Here&#8217;s a Simple Plan to Fix It</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 01 Nov 2015 17:59:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"WPTavern: WordPress 4.4 Streamlines Content Sharing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48797\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"http://wptavern.com/wordpress-4-4-streamlines-content-sharing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4151:\"<p>For the last six years, WordPress has been an <a href=\"https://codex.wordpress.org/Embeds\">oEmbed consumer</a>, adding support for services with nearly every major release since 2.9. In WordPress 4.4, it switches roles and is an oEmbed provider.</p>\n<p>Proposed by Pascal Birchler <a href=\"https://make.wordpress.org/core/2015/09/30/feature-plugin-merge-proposal-oembed/\">earlier this year</a>, oEmbeds for posts streamlines how they&#8217;re shared across the web. Here&#8217;s an example of what an oEmbedded post looks like.</p>\n<p></p>\n<p>Content is displayed in an iFrame with a link to comments, a sharing button, and a link to the main page the article is hosted on. The continue reading link takes visitors to the source site. In the last three months, Birchler and members of the core team have worked hard to make sure embedded content is secure.</p>\n<ul>\n<li>The iFrames use the <a href=\"https://developer.mozilla.org/en/docs/Web/HTML/Element/iframe#Attributes\">sandbox attribute</a> to enable extra restrictions on content that can appear in the inline frame.</li>\n<li>The host and the embedded site communicate via postMessage to allow resizing and clicking on links safely</li>\n</ul>\n<p>oEmbed discovery is turned on by default in WordPress 4.4. Too disable it, you&#8217;ll need install and activate the <a href=\"https://wordpress.org/plugins/disable-embeds/\">Disable Embeds</a> plugin. The plugin does the following:</p>\n<ul>\n<li>Prevents others from embedding your site.</li>\n<li>Prevents you from embedding other non-whitelisted sites.</li>\n<li>Disables all JavaScript</li>\n</ul>\n<p>Some people <a href=\"https://make.wordpress.org/core/2015/10/28/new-embeds-feature-in-wordpress-4-4/#comment-28263\">are requesting</a> that an option be added to disable oEmbeds rather than installing a plugin. In response to requests, Aaron Jorbin, WordPress core contributor, reemphasized <a href=\"https://wordpress.org/about/philosophy/#decisions\">WordPress&#8217; philosophy</a> on adding options.</p>\n<blockquote><p>Every time you give a user an option, you are asking them to make a decision. When a user doesn’t care or understand the option this ultimately leads to frustration. As developers we sometimes feel that providing options for everything is a good thing, you can never have too many choices, right?</p>\n<p>Ultimately these choices end up being technical ones, choices that the average end-user has no interest in. It’s our duty as developers to make smart design decisions and avoid putting the weight of technical choices on our end users.</p></blockquote>\n<p>Birchler also responded saying, &#8220;The new embed functionality was developed with the majority of users in mind.&#8221; One of the largest problems with adding to options to WordPress is that they&#8217;re difficult to remove.</p>\n<p>Some WordPress developers are excited to see how post embeds can be extended. <a href=\"http://hughlashbrooke.com/\">Hugh Lashbrooke</a>, who works for Automattic, thinks post embeds will be great for Custom Post Types, &#8220;I think the oEmbed feature has loads of awesome use cases for Custom Post Types. For example, being able to embed eCommerce products on other sites with dynamic add to cart links,&#8221; he said.</p>\n<p>The easiest way to try post embeds is to log into <a href=\"http://wptavern.com/test-new-wordpress-features-without-installing-anything-via-trywpbeta\">TryWPBeta</a> using these credentials.</p>\n<ul>\n<li><strong>Username</strong>: wcpdx</li>\n<li><strong>Password</strong>: wcpdx15</li>\n</ul>\n<p>Create a new post and make sure the visual editor is selected. Copy a URL from one of the Make Core WordPress blog posts and paste it into the editor.</p>\n<p>If you&#8217;d like to learn more about how this feature works, check out <a href=\"https://make.wordpress.org/core/2015/10/28/new-embeds-feature-in-wordpress-4-4/\">Birchler&#8217;s post</a> where he explains what developers need to take note of and how to customize the output. WordPress 4.4 is <a href=\"https://make.wordpress.org/core/version-4-4-project-schedule/\">scheduled for release</a> in December.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 30 Oct 2015 20:50:22 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"Matt: Lifehacker Japan\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45539\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"http://ma.tt/2015/10/lifehacker-japan/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:301:\"<p>When I was last in Tokyo <a href=\"http://www.lifehacker.jp/2015/10/151022wordpress_matt.html\">I sat down with Lifehacker Japan and they have a long interview in Japanese and some photos from the trip</a>. I don&#8217;t remember what I said, but the Google Translate version is pretty hilarious.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 30 Oct 2015 20:11:55 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"WPTavern: WPWeekly Episode 211 – Kyle Maurer Co-founder of Real Big Marketing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48791\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"http://wptavern.com/wpweekly-episode-211-kyle-maurer-co-founder-of-real-big-marketing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2590:\"<p>In this episode, <a href=\"http://marcuscouch.com/\">Marcus Couch</a> and I are joined by Kyle Maurer, Co-founder of <a href=\"http://realbigmarketing.com/\">Real Big Marketing. </a>Maurer grew up in rural Michigan working on farms without much knowledge of the IT industry. He registered an account on meetup.com after discovering a WordPress meetup in his local area.</p>\n<p>During the meetup, Maurer discovered how powerful WordPress is. The knowledge he gained motivated him to dive deep into WordPress and eventually start his own development agency.</p>\n<p>We discuss his most recent project, <a href=\"http://wordcrash.net/\">WordCrash,</a> which allows people in the WordPress community to offer travelers a place to stay for free. We also discuss his involvement with <a href=\"http://wordpress.tv/\">WordPress.TV</a> where Maurer volunteers to moderate videos, contribute code to the site, and coordinate projects. Last but not least, we discuss <a href=\"http://wproundtable.com/\">WP Roundtable</a>, a weekly WordPress podcast hosted by Maurer and a <a href=\"http://wproundtable.com/panel/\">panel of WordPress personalities</a>.</p>\n<h2>Stories Discussed:</h2>\n<p><a href=\"https://wordpress.org/news/2015/10/wordpress-4-4-beta-2/\">WordPress 4.4 Beta 2 Released</a></p>\n<h2>Plugins Picked By Marcus:</h2>\n<p><a href=\"https://wordpress.org/plugins/media-deduper/\">Media DeDuper</a> saves disk space and brings some order to the chaos of your media library by removing and preventing duplicate files.</p>\n<p><a href=\"https://wordpress.org/plugins/feature-request/\">Feature Request</a> is an advanced feature request and suggestion submitter with a built-in voting system for WordPress.</p>\n<p><a href=\"https://wordpress.org/plugins/minimum-dimensions-for-image-field/\">Minimum Dimensions For Image Field</a> allows the user to set size constraints for the Featured Image field.</p>\n<h2>WPWeekly Meta:</h2>\n<p><strong>Next Episode:</strong> Wednesday, November 4th 9:30 P.M. Eastern</p>\n<p><strong>Subscribe To WPWeekly Via Itunes: </strong><a href=\"https://itunes.apple.com/us/podcast/wordpress-weekly/id694849738\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via RSS: </strong><a href=\"http://www.wptavern.com/feed/podcast\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via Stitcher Radio: </strong><a href=\"http://www.stitcher.com/podcast/wordpress-weekly-podcast?refid=stpr\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Listen To Episode #211:</strong><br />\n</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 30 Oct 2015 16:50:45 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"WPTavern: Joe McGill Explains How Responsive Images Work in WordPress 4.4\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48780\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"http://wptavern.com/joe-mcgill-explains-how-responsive-images-work-in-wordpress-4-4\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2895:\"<p>One of the key features in WordPress 4.4 is <a href=\"https://make.wordpress.org/core/2015/09/30/responsive-images-merge-proposal/\">responsive images</a>. Joe McGill, who is helping to merge the feature to core, joined me for a thirty minute interview to explain how it works.</p>\n<p>When users upload images in WordPress, it automatically crops new images to smaller sizes. For example, if you upload an image that&#8217;s 1500 x 706, the image sizes might look like this:</p>\n<ul>\n<li>Full Size &#8211; 1500 x 706</li>\n<li>Large &#8211; 500 x 235</li>\n<li>Medium &#8211; 300 x 141</li>\n<li>Thumbnail &#8211; 150 x 150</li>\n</ul>\n<p>Additional sizes are created depending on the theme. If the full size image is attached to a post, users on desktop and mobile devices will see the full size image. However, it doesn&#8217;t make sense to use the full size image on mobile devices because of its display and file size.</p>\n<p>Responsive images in WordPress 4.4 adds <code>srcset</code>&nbsp;and <code>sizes</code> support to WordPress. This allows the software to automatically use and display the right image based on a device&#8217;s screen size. If I attach a full size 1500 x 706 image to a post in WordPress 4.4, mobile devices will see the large or medium-sized image instead.</p>\n<p>Responsive images don&#8217;t have any settings to configure as the magic happens behind the scenes. I encourage you to listen to the interview as it may be easier to understand listening to us talk through the feature.</p>\n<div class=\"audio-shortcode-wrap\"><img src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/ResponsiveImagesinWordPress.png?resize=175%2C131\" alt=\"Responsive Images in WordPress\" class=\"landscape thumbnail post-thumbnail audio-image\" /><!--[if lt IE 9]><script>document.createElement(\'audio\');</script><![endif]-->\n<a href=\"http://wptavern.com/wp-content/uploads/2015/10/Joe-McGill-Explains-Responsive-Images-in-WordPress.mp3\">http://wptavern.com/wp-content/uploads/2015/10/Joe-McGill-Explains-Responsive-Images-in-WordPress.mp3</a></div><div class=\"media-shortcode-extend\"><div class=\"media-info audio-info\"><ul class=\"media-meta\"><li><span class=\"prep\">Run Time</span> <span class=\"data\">26:50</span></li><li><span class=\"prep\">Artist</span> <span class=\"data\">Jeff Chandler</span></li><li><span class=\"prep\">File Name</span> <span class=\"data\"><a href=\"http://wptavern.com/wp-content/uploads/2015/10/Joe-McGill-Explains-Responsive-Images-in-WordPress.mp3\">Joe-McGill-Explains-Responsive-Images-in-WordPress.mp3</a></span></li><li><span class=\"prep\">File Size</span> <span class=\"data\">12.09 MB</span></li><li><span class=\"prep\">File Type</span> <span class=\"data\">MP3</span></li><li><span class=\"prep\">Mime Type</span> <span class=\"data\">audio/mpeg</span></li></ul></div><button class=\"media-info-toggle\">Audio Info</button></div>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 29 Oct 2015 00:43:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"WPTavern: The WordPress Theme Directory No Longer Counts Automated Downloads\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48766\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"http://wptavern.com/the-wordpress-theme-directory-no-longer-counts-automated-downloads\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5745:\"<p>The <a href=\"https://wordpress.org/themes/browse/popular/\">popular themes page</a> on the WordPress theme directory usually displays a mix of default themes and those that meet a certain criteria. While the criteria to reach the page is not publicly known, download counts are one form of measurement.</p>\n<p>Since September, the <a href=\"https://wordpress.org/themes/swift/\">Swift theme</a> has routinely shown up on the popular themes page. According to download stats, Swift was downloaded between, 2,000 to 3,500 times a day in September and early October.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/SwiftThemeDownloadNumbers.png\"><img class=\"size-full wp-image-48767\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/SwiftThemeDownloadNumbers.png?resize=665%2C500\" alt=\"Swift Download Count\" /></a>Swift Download Count\n<p>However, the stats drop off abruptly on October 15th and have yet to reach previous levels. On October 18th, a few members inside the Theme Review Team Slack channel <a href=\"https://wordpress.slack.com/archives/themereview/p1445155458000095\">shared suspicions</a> that something was not right with Swift&#8217;s download stats.</p>\n<p>Ionut Neagu discovered that Swift does not appear on the <a href=\"https://garage.godaddy.com/top-100-wordpress-themes/\">GoDaddy Hot 100</a> while other themes on the popular page do. While not conclusive, the evidence points towards some sort of anomaly.</p>\n<p>Samuel &#8216;Otto&#8217; Wood, who helps maintain WordPress.org <a href=\"https://wordpress.slack.com/archives/themereview/p1445180169000105\">looked at the raw</a> data for Swift and discovered that a lot of the downloads appeared to be automated.</p>\n<blockquote><p>The swift theme is indeed getting an exceptional number of downloads, so I took a closer look at the raw data. It appears that a lot of these downloads are automated in some way. However, there&#8217;s no evidence that it is malicious, nor does the pattern apply only to the swift theme. Perhaps it is included in some installer system that auto-downloads themes for newly installed sites. It&#8217;s hard to say.</p>\n<p>In any case, I made a way to detect and block these types of automated downloads from appearing in the stats, and retroactively applied it for the last three days of data (which is all we retain). Going forward, automated downloads will not appear as downloads and will not affect the popular listings.</p></blockquote>\n<p>Once the changes were implemented, Swift&#8217;s download stats significantly decreased. The changes also apply to all other themes hosted on the directory. Otto declined to comment on the specific changes made but tells the Tavern, &#8220;If we can detect a case where downloads aren&#8217;t being made by users, then we will try not to count it in the results.&#8221;</p>\n<h2>Swift’s Side of the Story</h2>\n<p>Satish Gandham, founder of <a href=\"https://swiftthemes.com/\">Swiftthemes</a>, explains what Swift has gone through the last few weeks which may account for the high download numbers, &#8220;Swift was featured for a couple of days and we spent money on Facebook ads to promote the free version. Also, there were a couple of hosted WordPress providers who asked permission to include Swift on their platform.</p>\n<p>&#8220;The premium version of Swift also had the same slug URL as the free version. The WordPress theme directory saw v7.2.48 to be higher than 7.2.6 and premium users downgraded to the free version thinking it was an upgrade. It was a support nightmare,&#8221; Gandham tells the Tavern.</p>\n<p>Swift&#8217;s <a href=\"https://swiftthemes.com/forums/topic/how-to-returning-to-version-7-2-6/\">support forums</a> confirm that some customers of the commercial version were automatically updated to the free version in early August.</p>\n<h2>Download Counts are Almost Irrelevant</h2>\n<p>When the <a href=\"http://wptavern.com/wordpress-plugin-directory-launches-new-design\">plugin directory was redesigned</a> earlier this year, download counts were removed in favor of active installs. Active installs are more accurate and difficult to manipulate. On the other hand, when the <a href=\"http://wptavern.com/wordpress-theme-directory-launches-new-design\">theme directory was redesigned</a>, download counts remained.</p>\n<p>It&#8217;s possible that the theme directory will one day show active installs but the data gathering aspect is not ready yet. Also, the numbers are lower for themes than for plugins, which may lead to incorrect conclusions in regards to relative popularity.</p>\n<h2>It Happens More Than You Might Think</h2>\n<p>In this particular instance, there&#8217;s no evidence that points to a malicious intent to inflate stats to manipulate the popular themes page. In the years I&#8217;ve written about WordPress, I&#8217;ve heard rumors that certain plugins and themes automate their download counts to appear more popular than they really are. However, I&#8217;ve yet to write about a theme or plugin caught in the act.</p>\n<p>According to Otto, it happens more often than you might think. When he or other volunteer moderators for the plugin and theme directories notice fishy download counts, they contact the author and the process usually stops. If it continues, the author risks having their themes and plugins suspended or banned from the directory.</p>\n<p>If you notice suspicious activity with a theme hosted on WordPress.org, you can voice your concern in the <a href=\"https://make.wordpress.org/chat/\">Theme Review Slack</a> channel during non-meeting times. For suspicious activity related to plugins hosted on the directory, email <strong>plugins at WordPress.org</strong>.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 28 Oct 2015 20:23:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"Post Status: Using WordPress as an application framework — Draft podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://poststatus.com/?p=14800\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://poststatus.com/using-wordpress-as-an-application-framework-draft-podcast/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2324:\"<p>Welcome to the Post Status Draft podcast, which you can find <a href=\"https://itunes.apple.com/us/podcast/post-status-draft-wordpress/id976403008\">on iTunes</a> and <a href=\"http://simplecast.fm/podcasts/1061/rss\">via RSS</a> for your favorite podcatcher. Brian and his co-host, <a href=\"https://twitter.com/joe_hoyle\">Joe Hoyle</a>, a co-founder and the CTO of <a href=\"https://hmn.md/\">Human Made</a>, discuss some of today’s hottest, current WordPress news.</p>\n<p>In this episode of Draft, Joe and Brian discuss a popular site’s redesign, and how the developers viewed WordPress’s shortcomings. They also talk about WordPress’s chops generally for complex sites and applications.</p>\n<p><!--[if lt IE 9]><script>document.createElement(\'audio\');</script><![endif]-->\n<a href=\"https://audio.simplecast.fm/19270.mp3\">https://audio.simplecast.fm/19270.mp3</a><br />\n<a href=\"https://audio.simplecast.fm/19270.mp3\">Direct Download</a></p>\n<p><strong>Topics:</strong></p>\n<h3>An outside look at WordPress</h3>\n<ul>\n<li><a href=\"https://poststatus.com/notes/wordpress-shortcomings-from-developers-that-prefer-other-software/\">WordPress shortcomings, from developers that prefer other software</a></li>\n<li><a href=\"http://responsivewebdesign.com/toast/backend/\">Redesigning The Toast</a></li>\n<li><a href=\"http://upstatement.com/timber/\">Timber, Twig templating for WordPress</a></li>\n<li><a href=\"http://blog.apps.chicagotribune.com/2011/10/19/turning-wordpress-into-a-framework-with-mtv/\">WordPress MTV</a></li>\n<li><a href=\"http://www.advancedcustomfields.com/\">Advanced Custom Fields </a></li>\n<li><a href=\"http://cmb2.io/\">CMB2</a></li>\n</ul>\n<h3>WordPress as an application framework</h3>\n<ul>\n<li><a href=\"https://pippinsplugins.com/series/building-a-database-abstraction-layer/\">Building a database abstraction layer</a></li>\n<li><a href=\"https://nomadbase.io/\">Nomad Base</a></li>\n<li><a href=\"https://github.com/10up/ElasticPress\">ElasticPress, by 10up</a></li>\n<li><a href=\"https://github.com/alleyinteractive/searchpress\">SearchPress, by Alley</a></li>\n<li><a href=\"https://developer.wordpress.com/docs/elasticsearch/\">Elasticsearch on WordPress.com</a></li>\n<li><a href=\"https://vip.wordpress.com/2015/07/08/scaling-wp-queries-with-elasticsearch/\">Scaling WP queries with Elasticsearch</a></li>\n</ul>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 28 Oct 2015 04:05:24 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Katie Richards\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"WPTavern: ManageWP Launches Orion Dashboard\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48756\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"http://wptavern.com/managewp-launches-orion-dashboard\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2334:\"<p>If you use <a href=\"https://managewp.com/\">ManageWP</a>, you may have noticed a new dashboard design. That&#8217;s because the <a href=\"https://managewp.com/developer-diary-9-managewp-orion-is-out\">company released Orion</a>, a completely redesigned dashboard for managing sites.</p>\n<p>To give users a chance to alter workflows and explore the Orion dashboard, ManageWP linked the original dashboard to Orion. Actions performed in one dashboard are mirrored to the other. Users can switch between the two with the click of a button.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/ManageWPOrianOldNew.gif\"><img class=\"size-full wp-image-48757\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/ManageWPOrianOldNew.gif?resize=638%2C512\" alt=\"ManageWP Dashboard Compared to Orion\" /></a>ManageWP Dashboard Compared to Orion\n<p>Users can now sort sites by tags and clients in addition to groups. Websites can be assigned to clients while tags can describe whether a site is in development or live. Each site can up to five tags and one client.</p>\n<p>Unlike the native dashboard, Orion uses Angular.js which allows users to run asynchronous calls. For example, you can run more than one command why performing other tasks.</p>\n<p>One distinct difference between both dashboards is the way backups are generated. ManageWP backups and Orion backups are <a href=\"https://managewp.com/managewp-orion-developer-diary-3-bulletproof-backup-solution\">completely different</a> from each other. However, you can use both at the same time.</p>\n<p>The company says Orion comes with essential features but additional features will be completed and added by February of 2016 which is also when Orion will become the default dashboard. WordPress Multisite is not supported as the company cites it as a major undertaking and doesn&#8217;t consider it a high priority.</p>\n<p>The new dashboard contains more features than what&#8217;s listed here. I encourage you to read the <a href=\"https://managewp.com/developer-diary-9-managewp-orion-is-out\">official announcement</a> and if you&#8217;re a customer, to explore Orion as it will soon be the default experience to managing sites. If you&#8217;re a ManageWP customer, let us know what you think of the new dashboard design.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 27 Oct 2015 18:09:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"WPTavern: How to Prepare and Take Advantage of Language Packs for Plugins Hosted on WordPress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48727\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"http://wptavern.com/how-to-prepare-and-take-advantage-of-language-packs-for-plugins-hosted-on-wordpress-org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:15607:\"<hr />\n<p>This is a guest post contributed by <a href=\"https://mpswp.wordpress.com/\">Matthew Sparrow</a> who is a young, self-taught developer with minimal coding knowledge that loves to use WordPress. He mostly uses WordPress for personal projects although he has completed a couple of projects for others. In addition to <a href=\"https://profiles.wordpress.org/kidsguide/\">maintaining a few plugins</a>, he&#8217;s an active translations contributor.</p>\n<hr />\n<p>Automatic translations for plugins have been a long time coming. WordPress itself already auto-downloads and auto-updates core translations, so it is a natural progression that plugins and themes will receive the same treatment.</p>\n<p>For those who have been following auto plugin translations, it has <a href=\"http://ottopress.com/2013/language-packs-101-prepwork/\">been in the works for years</a>. It came as a welcome surprise in September when it was announced that plugins will <a href=\"https://make.wordpress.org/plugins/2015/09/01/plugin-translations-on-wordpress-org/\">finally be able to have language packs</a>.</p>\n<p>If you have a plugin in the WordPress.org directory, then this is important, welcome, and exciting news. However, as great as an initiative as language packs are for plugins, it <em>seems</em> simpler than it actually is.</p>\n<p>If you are a plugin developer, you have to go through a few steps in order to get this to work for your plugins. So let’s get started.</p>\n<h2 class=\"font-headlines\">Should You Be Excited About Plugin Language Packs?</h2>\n<p>As a plugin author, I&#8217;m really excited about the new translation system, and so should you. The <a href=\"https://make.wordpress.org/polyglots/\">Polyglots team</a> is making it so that you no longer have to include all of your <code>.mo</code> and <code>.po</code> files directly in your plugin. Instead, they will be hosted on WordPress.org.</p>\n<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-1.png\"><img class=\"aligncenter size-full wp-image-48731\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-1.png?resize=582%2C575\" alt=\"screenshot-1\" /></a>The ideal scenario is when a user selects their language (either through a new WordPress install or through <code>Settings &gt; General</code>), the language pack for your plugin will be automatically installed and kept updated.</p>\n<p>This new system accomplishes a few things:</p>\n<ul>\n<li>Plugin files are smaller. There&#8217;s no need to include translation files with your plugin.</li>\n<li>Plugin authors no longer need to manage translations/translators.</li>\n<li>End users are automatically able to see a plugin in their own language assuming a translation has already been created for their locale.</li>\n</ul>\n<h2 class=\"font-headlines\">How to Prepare for Plugin Language Packs</h2>\n<p>Before we jump into translating plugins, you first need to prepare your plugin for it to work with the new translation setup.</p>\n<p>In order for you to get your plugin prepared to be moved over to the new system, you need to change your text domain to exactly match your WordPress plugin slug. An important reminder is that even if you have changed your plugin&#8217;s name (as <a href=\"https://wordpress.org/plugins/wordpress-seo/\">Yoast SEO</a> recently did), the slug does not change. For a more in-depth discussion and tutorial, please follow Otto&#8217;s great post on <a href=\"http://ottopress.com/2013/language-packs-101-prepwork/\">language pack prepwork</a>.</p>\n<p>You are still welcome to include translation files in your plugin, even with language packs enabled. Translation files in your plugin take priority, and if those aren&#8217;t present, that&#8217;s where language packs come in.</p>\n<p>When you are preparing your plugin for language packs, it is important to note that you should avoid removing translation files from your plugin. If you do so, and your plugin is selected for language packs, your existing translations will not be automatically moved over to the new system.</p>\n<p>Do your best to keep your translation files with your plugin until the Polyglots team has informed you that your plugin is ready for language packs.</p>\n<h2 class=\"font-headlines\">Wait to Receive the Official Notice</h2>\n<p>The Polyglot team is preparing the plugins in stages to avoid any major hiccups. Assuming your WordPress.org email is up-to-date, you will receive an email when your plugin is ready.</p>\n<p>You may be wondering how long it takes before the team reaches your plugin. There are 40,000+ plugins on WordPress.org, so it is not a quick process. WordPress is preparing plugins in batches according to the amount of active installs each plugin has.</p>\n<p>If your plugin has over 30,000+ active installs, then chances are you are on the new system, although I&#8217;ve seen plugins with 10,000+ active installs also be approved.</p>\n<p>Unfortunately, there is no way to make the process quicker. Please practice patience and eventually your turn will come.</p>\n<h2 class=\"font-headlines\">You’ve Received the E-Mail That Your Plugin Is Ready</h2>\n<p>So you finally receive the email saying that your plugin is going to be uploaded with language pack support. Awesome! This is what the email that I received looks like. Note that I&#8217;m using one of my approved plugins as an example.</p>\n<blockquote><p>Howdy!<br />\n​<br />\nWe&#8217;re emailing you because you&#8217;re an author for the following plugin on WordPress.org:<br />\n​<br />\n* Easy Updates Manager : https://wordpress.org/plugins/stops-core-theme-and-plugin-updates/<br />\n​<br />\nNext week, we intend to import the plugin listed above into the translate.wordpress.org translation system. Language packs will also be enabled for your plugin, for any locales that are fully translated (at 100%).<br />\n​<br />\nAs part of this process, all of the strings in your plugin will be imported into translate.wordpress.org. Additionally, any language files that you ship with your plugin (&#8216;mo&#8217; files) will be imported and synced with their respective locales within translate.wordpress.org.<br />\n​<br />\nNo strings in your plugin? Plugin translations include the ability to translate the readme and display these translations in the localized WordPress.org plugin directories.</p>\n<p>If you have prepared your plugin already then this notice is of no real importance. If you have not yet prepared your plugin and you have received the notice then you need to prepare your plugin ASAP. If you don’t prepare your plugin then… well… I don’t really know, but it won’t be good. So go and prepare your plugin if you have not yet done so.<br />\n&#8230;</p></blockquote>\n<h2 class=\"font-headlines\">Your Plugin Is Semi-Ready for Language Packs. Now What?</h2>\n<p><a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-22.png\"><img class=\"alignright wp-image-48741 size-full\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-22.png?resize=291%2C321\" alt=\"screenshot-22\" /></a>A week or so after you receive the notice, your plugin and its translations are moved to <a href=\"https://translate.wordpress.org\">translate.wordpress.org</a>. You will likely not receive a notice when your plugin is moved.</p>\n<p>To find out if it&#8217;s been uploaded, visit your plugin&#8217;s WordPress.org page where you should see a translations section in the right sidebar. Click the <strong>Translate Plugin Name </strong>button<strong>.</strong> If you are brought to a page that looks like the one below then your plugin is uploaded and is ready to be translated.</p>\n<p><a href=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-3.png\"><img class=\"aligncenter size-full wp-image-48734\" src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-3.png?resize=954%2C611\" alt=\"screenshot-3\" /></a>If you see a page that looks different from this (i.e., a Not Found error), your plugin is not yet ready.</p>\n<p>Assuming you&#8217;ve received the e-mail, your plugin is ready, and you&#8217;ve waited a reasonable amount of time, you should be good to go as far as preparing your plugin.</p>\n<p>If it has been over two weeks and your plugin has not yet been uploaded, you should contact the Polyglot team <a href=\"https://make.wordpress.org/polyglots/\">on their blog</a>, or in the <a href=\"https://make.wordpress.org/chat/\">#polyglots channel on WordPress Slack</a>. Please exercise extreme patience as the process can take a week or sometimes even two.</p>\n<h2 class=\"font-headlines\">Removing Your Translation Files From Your Plugin</h2>\n<p>Now that your plugin is uploaded to the system, you can safely remove the translation files from your plugin. If you don’t have any <code>.mo</code> and <code>.po</code> files in your plugin, then you can skip this step.</p>\n<p>One thing to note: You may not want to remove your translation files if your plugin does not have any translations on <a href=\"https://translate.wordpress.org/\">translate.wordpress.org</a> or translations are not 100% complete.</p>\n<h2 class=\"font-headlines\">Making Your Plugin Translatable</h2>\n<p>With all of that stuff out-of-the-way, it’s time to focus on translating your plugin. This is where it can get confusing but try to stick with me.</p>\n<p>By default, you cannot submit translations for your plugin in any language. Because of this, you need to ask the Polyglots team to add you as a translator for your plugin. You can do so by heading over to the <a href=\"https://make.wordpress.org/polyglots/\">Polyglots blog</a> and ask them. To make it easier they came up with a template of <a href=\"https://make.wordpress.org/polyglots/handbook/rosetta/theme-plugin-directories/#sample-post\">what to say</a>.</p>\n<blockquote><p>Hello Polyglots!</p>\n<p>I am the plugin author for [plugin-name and link to plugin directory]. We have a number of great translation editors that we’d like to be able to approve translation for our plugin(s). Please add the following WordPress.org users as translation editors for their respective locales:<br />\no #ar – @username<br />\no #bn – @username, @username<br />\no #da – @username<br />\no #de-ch – @username<br />\netc…</p>\n<p>If you have any questions, just comment here. Thank you!</p></blockquote>\n<p>Ideally, the above will include requests for multiple plugins, but as plugins are being rolled out slowly, it&#8217;s acceptable at the moment to include one request per plugin.</p>\n<p>Make sure that you use WordPress.org usernames and that the user is still active. If you are wondering what languages there are, you can visit <a href=\"https://translate.wordpress.org/\">https://translate.wordpress.org/</a> and scroll through the different languages that WordPress supports.</p>\n<p>Please only ask to be added as a translator for the languages you know. You will not be approved if you are not a native speaker for a language.</p>\n<p>At this point, again, patience is needed. The Polyglot team will receive your request and will work through it. If your post doesn&#8217;t show up right away, it&#8217;s because first-time posters are moderated.</p>\n<p>In a week or two, the translators you requested should be added to your plugin. If there are any issues, a Polyglot member will comment on your request with any difficulties encountered or notify you that they have approved your request.</p>\n<p>You&#8217;ll know when you are added when you see new badges appear on your WordPress.org profile page. One is a translation editor badge and the other is a translation contributor badge.</p>\n<h2><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-4.png\"><img class=\"aligncenter size-full wp-image-48735\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-4.png?resize=601%2C322\" alt=\"screenshot-4\" /></a>How Do I Translate?</h2>\n<p>First, visit <a href=\"https://translate.wordpress.org/\">https://translate.wordpress.org/</a>, select your language, then click the plugins tab. Search for your plugin and then click the translate project button. You&#8217;ll be brought to a page that looks like the one below. This page is where you can translate your plugin. In this case, my plugin is already translated in the language that I selected.</p>\n<p><a href=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-5.png\"><img class=\"aligncenter size-full wp-image-48736\" src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-5.png?resize=957%2C587\" alt=\"screenshot-5\" /></a>On this table, there are four separate things to translate. Trunk, the stable release (version), and the <code>readme.txt</code> variations. In order for language packs to work, <em>you need to translate all four versions</em>.</p>\n<p>To translate, click on one of the sub-projects. This takes you to the translation page. Here, you can see all of the different strings that need to be translated in your plugin. You can edit a string by clicking the details button, translating it in the text editor, and then clicking the <strong>add translations</strong> button.</p>\n<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-6.png\"><img class=\"aligncenter size-full wp-image-48737\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-6.png?resize=947%2C561\" alt=\"screenshot-6\" /></a>Even if you&#8217;re not added as an editor for a language, you can still translate a plugin. The only difference is instead of adding the translations directly, you can only request that it be changed. Someone from the Polyglots team will need review and approve your translation suggestions.</p>\n<h2 class=\"font-headlines\">Once Your Translations Are Ready</h2>\n<p>Once you&#8217;ve finished translating a language completely, it will be available for people to use. However, it doesn’t become available immediately. It can take one to three days for a translation to be available once you finish it. Again, exercise patience.</p>\n<p>You&#8217;ll know when the translation is available when you see it in the translation section on your WordPress.org plugin&#8217;s page. For example, you can see what it looks like in the picture below.</p>\n<p><a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-7.png\"><img class=\"aligncenter size-full wp-image-48744\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/screenshot-7.png?resize=447%2C377\" alt=\"screenshot-7\" /></a>Also, you&#8217;ll know it&#8217;s working if you go into a website (preferably not a live website), download your plugin, and select the language that you want to test in <strong>Settings &gt; General</strong>.</p>\n<h2 class=\"font-headlines\">Plugin Language Packs Are Here to Stay</h2>\n<p>Getting language packs to work properly in WordPress plugins is not exactly a straightforward process, which is precisely why plugins are being rolled out slowly.</p>\n<p>Please remember that everyone is a volunteer, from the Polyglots team, to translators, and to the plugin authors. Please give props where appropriate as everyone is working hard to make plugin language packs the norm.</p>\n<p>If you are having any trouble, the Polyglots team also has a <a href=\"https://make.wordpress.org/polyglots/handbook/\">handbook</a> available which provides some good information on how this new system works.</p>\n<p>I&#8217;ll also do my best to answer any questions in the comment section. If you have additional insight, please weigh in as well.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 27 Oct 2015 02:52:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"WPTavern: Test New WordPress Features Without Installing Anything via TryWPBeta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48713\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"http://wptavern.com/test-new-wordpress-features-without-installing-anything-via-trywpbeta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3568:\"<p>Over the weekend at <a href=\"https://portland.wordcamp.org/2015/\">WordCamp Portland, Oregon</a>, Drew Jaynes, a WordPress core developer who also led the 4.2 development cycle presented on the topic of beta testing WordPress.</p>\n<p>In the presentation, Jaynes highlights the pros and cons of using the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Testing plugin</a> on a testing site and a production site. However, he also cites a third way to test WordPress via <a href=\"http://wcpdx.trywpbeta.com/\">TryWPBeta.com</a>.</p>\n<p> \n<div> <strong> <a href=\"https://www.slideshare.net/DrewAPicture/trying-out-tomorrows-wordpress-today\" title=\"Trying Out Tomorrow’s WordPress Today\" target=\"_blank\">Trying Out Tomorrow’s WordPress Today</a> </strong> from <strong><a href=\"http://www.slideshare.net/DrewAPicture\" target=\"_blank\">DrewAPicture</a></strong> </div>\n<p>TryWPBeta is a locked down, vanilla install of WordPress trunk using Multisite. To login to the site, use the following credentials.</p>\n<ul>\n<li><strong>Username</strong>: wcpdx</li>\n<li><strong>Password</strong>: wcpdx15</li>\n</ul>\n<p>I asked Jaynes what inspired him to create the site, &#8220;The inspiration for TryWPBeta is to actually have a place for core contributors to test patches on mobile devices, because setting up a tunnel to a local development setup is difficult and a high barrier for a lot of people.&#8221;</p>\n<p>The idea is to make it possible to spin up a site using trunk (Bleeding edge version of WordPress), apply a specific patch and then freeze it in time so that we can point people there to test on mobile devices,&#8221; Jaynes told the Tavern.</p>\n<p>While you can&#8217;t install themes and plugins yet, the site gives users an opportunity to test new features without worrying about breaking the site. Thanks to TryWPBeta, I was able to test the new <a href=\"https://core.trac.wordpress.org/changeset/34903\">Post oEmbed feature</a> in 4.4.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/TestingPostoEmbeds.png\"><img class=\"size-full wp-image-48714\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/TestingPostoEmbeds.png?resize=1025%2C458\" alt=\"Testing oEmbeds of Posts\" /></a>Testing oEmbeds of Posts\n<p>Jaynes started the project at 10up&#8217;s company summit. So far, Scott Reilly, John Blackbourn, Zach Brown, Morgan Estes, and Chris Weigman have contributed to the project. The site is hosted on a DigitalOcean droplet and updates hourly. He stresses that the site is a work in progress and not quite ready for prime time, &#8220;There’s a couple features I’d like to add to make it more robust first,&#8221; Jaynes said.</p>\n<p>Unlike <a href=\"https://demo.joomla.org/\">Joomla</a>, WordPress doesn&#8217;t have a dedicated demo site for users to test drive the software. While I like the idea behind TryWPBeta, there are a few things I&#8217;d like to see added to make it more useful. For instance, a list of items to test that users can check off. Also, an easy way to provide feedback on the listed items that is sent to a place where core developers will read it.</p>\n<p>Ultimately, I&#8217;d like to see the WordPress Beta Testing plugin extended to have the features I mentioned above. Between the communication challenges and setting up the environment, the beta testing process in WordPress is not as easy and streamlined as it could be. What ideas do you have that would help increase the testing audience and make the process easier?</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 27 Oct 2015 00:37:45 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"WPTavern: VersionPress Raises $400K in Seed Funding\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48709\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"http://wptavern.com/versionpress-raises-400k-in-seed-funding\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2780:\"<p><a href=\"http://versionpress.net/\">VersionPress</a>, a version control plugin for WordPress, has <a href=\"http://blog.versionpress.net/2015/10/seed-funding/\">raised $400K in seed funding</a> from five investors, led by <a href=\"http://www.credoventures.com/\">Credo Ventures</a> based in Prague. In July of 2014, VersionPress conducted a <a href=\"http://wptavern.com/versionpress-misses-crowdfunding-goal-by-14-5k\">crowdfunding campaign</a> to raise $30K. However, the team raised only <strong>45% of the $30,000</strong> funding goal.</p>\n<p>The team pressed on and released the first version back in January. Since then, the team has relied on funding from the <a href=\"http://versionpress.net/\">Early Access Program</a>. Borek Bernard, the lead developer of VersionPress, says the influx of cash will help fuel rapid development:</p>\n<blockquote><p>First and foremost, it means that we will be able to develop VersionPress at a more rapid pace. What we currently have in the <a href=\"http://blog.versionpress.net/2015/10/versionpress-2-0-released/\">recently released v2.0</a> is a great start but the vision and the technical challenge are just so large that this new fuel will is more than welcome. We have many cool features planned and this will allow us to deliver them in a timely manner.</p></blockquote>\n<p>The funding comes on the heels of <a href=\"http://blog.versionpress.net/2015/10/versionpress-2-0-released/\">VersionPress 2.0</a> which includes, database synchronization functionality and an updated user interface that is completely JavaScript based, along with a number of other features. In addition to funding, Bernard says talking to investors gives him a fresh perspective on the project:</p>\n<blockquote><p>One big benefit of talking to investors is that it provides a fresh perspective on the problems one is trying to solve, how to solve them, for whom, etc. Speaking to them made us realize a couple of important things which will greatly benefit our users down the road.</p></blockquote>\n<p>VersionPress joins a growing list of WordPress products and services that have raised venture capital. In 2014, <a title=\"http://wordpress.org/plugins/coschedule-by-todaymade/\" href=\"http://wordpress.org/plugins/coschedule-by-todaymade/\">CoSchedule</a>, the editorial workflow and activity scheduling plugin, <a title=\"http://coschedule.com/blog/coschedule-series-a-funding/\" href=\"http://coschedule.com/blog/coschedule-series-a-funding/\">secured $500K</a> in a Series A round of funding. Prior to being acquired by Automattic, <a href=\"http://wptavern.com/wordpress-service-provider-bruteprotect-secures-funding-forms-parka-llc\">BruteProtect secured a round of funding</a> from a private angel investor in California.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 26 Oct 2015 20:00:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Matt: .Ly Domains\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45516\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"http://ma.tt/2015/10/ly-domains/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:154:\"<p>Priceonomics on <a href=\"http://priceonomics.com/the-rise-and-fall-of-ly/\">The Rise and Fall of .Ly</a>. Some of my favorite domains I own are .ly.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 26 Oct 2015 19:04:57 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:13;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"WPTavern: Nikhil Vimal Acquires Front End Registration and Login Forms Plugin From Pippin Williamson\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48695\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:110:\"http://wptavern.com/nikhil-vimal-acquires-front-end-registration-and-login-forms-plugin-from-pippin-williamson\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2679:\"<p>Nikhil Vimal, who runs <a href=\"https://techvoltz.com/\">Techvoltz.com</a>, a WordPress development agency, <a href=\"https://techvoltz.com/blog/2015/10/23/new-plugin-front-end-registration-and-login-forms-plugin/\">is the new owner</a> of the <a href=\"https://techvoltz.com/downloads/front-end-registration-login-forms-plugin/\">Front End Registration and Login Forms Plugin</a> created by Pippin Williamson. Earlier this month, Williamson put the plugin up for sale and noted that it needed some development work.</p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">I would like to sell my Frontend Registration and Login Forms plugin. <a href=\"https://t.co/HLGc8OVxq4\">https://t.co/HLGc8OVxq4</a> &#8211; It needs some work. Interested? Ping me</p>\n<p>&mdash; Pippinsplugins (@pippinsplugins) <a href=\"https://twitter.com/pippinsplugins/status/651489362052431872\">October 6, 2015</a></p></blockquote>\n<p></p>\n<p>The plugin was created in December of 2011, when Williamson <a href=\"https://pippinsplugins.com/creating-custom-front-end-registration-and-login-forms/\">published a tutorial</a> that explains how to create custom front end registration and login forms for WordPress. Although Vimal is participating in the commercial plugin space by selling a <a href=\"https://ninjaforms.com/extensions/slack/\">Slack add-on for Ninja Forms</a>, this acquisition marks the first plugin sold directly from his site.</p>\n<p>With the acquisition, <a href=\"https://pippinsplugins.com/nikhil-vimal-adopts-front-end-registration-and-login-forms-plugin/\">Williamson notes</a> that existing customers will no longer be able to renew license keys on <a href=\"https://pippinsplugins.com\">Pippinsplugins.com</a>. A complete customer list was given to Vimal and Williamson is no long providing support.</p>\n<p>When the opportunity presented itself to adopt a plugin created by Williamson, Vimal jumped on it, &#8220;Shortly after I saw his tweet, I quickly contacted Pippin. His work is something I’ve always looked up to. His work on plugins has inspired me to pursue the plugin/product market,&#8221; Vimal said.</p>\n<p>Licenses start at $10 for single sites, $20 for two to five sites, and $35 for an unlimited number of sites. Vimal says that he is working on a new version with changes in design, functionality, and more. The plugin will also receive its own dedicated site with a change in branding.</p>\n<p>It will be interesting to see what changes Vimal has in store for the plugin. Until then, existing customers from Pippinsplugins.com should watch their inbox for details on renewing their subscription to TechVoltz.com.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 23 Oct 2015 20:02:38 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:14;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"WPTavern: WordPress 4.4 Beta 1 Released\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48687\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"http://wptavern.com/wordpress-4-4-beta-1-released\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4051:\"<p>After more than eight weeks in development, <a href=\"https://wordpress.org/news/2015/10/wordpress-4-4-beta-1/\">WordPress 4.4. beta 1 is available</a> for testing. With over <a href=\"https://github.com/WordPress/WordPress/compare/4.3-branch...master\">1,600 commits</a> since WordPress 4.3&#8217;s release, it&#8217;s important that 4.4 be tested by as many people as possible.</p>\n<p>Commits are bug fixes, additional functions or filters, new features, corrected typos, and anything inbetween. As a rule of thumb, think of commits as an incremental improvement to WordPress core.</p>\n<p>There are three new distinct user facing features in WordPress 4.4.</p>\n<ul>\n<li><strong>Twenty Sixteen</strong> &#8211; Twenty Sixteen is a <a href=\"http://wptavern.com/first-look-at-the-twenty-sixteen-default-wordpress-theme\">new default theme</a> with a simple layout and color scheme designed by <a href=\"https://profiles.wordpress.org/iamtakashi\">Takashi Irie,</a> who also designed the <a href=\"http://takashiirie.com/2013/12/13/twenty-fourteen-wordpress-3-8-parker/\">Twenty Fourteen</a> and <a href=\"http://takashiirie.com/2015/03/19/twenty-fifteen-the-wordpress-default-theme-for-2015/\">Twenty Fifteen</a> default themes.</li>\n<li><strong>Responsive Images</strong> &#8211; WordPress will automatically deliver a <a href=\"https://make.wordpress.org/core/2015/09/30/responsive-images-merge-proposal/\">more appropriate image</a> to users depending on a variety of conditions like screen size, view port size, and screen resolution.</li>\n<li><strong>oEmbed Posts</strong> &#8211; In addition to YouTube, WordCamp.TV and other whitelisted providers, users will be able to easily embed content from almost any site that supports the <a href=\"http://oembed.com/\">oEmbed standard</a>, including <a href=\"https://make.wordpress.org/core/2015/09/30/feature-plugin-merge-proposal-oembed/\">WordPress sites</a>.</li>\n</ul>\n<p>Scott Taylor, who is leading the 4.4 development cycle, gives developers at least four reasons to be excited.</p>\n<ul>\n<li><strong>REST API (phase 1) </strong>— The underlying infrastructure of the WordPress REST API <a href=\"https://wordpress.org/plugins/rest-api/\">plugin</a> is <a href=\"https://make.wordpress.org/core/2015/09/21/wp-rest-api-merge-proposal/\">included in WordPress 4.4</a>. Plugin authors can take advantage of this by adding custom endpoints.</li>\n<li><strong>Term Metadata </strong>— Taxonomy term metadata <a href=\"https://make.wordpress.org/core/2015/09/04/taxonomy-term-metadata-proposal/\">is included</a> in WordPress 4.4. Developers who are using a plugin to implement term metadata should <a href=\"https://make.wordpress.org/core/2015/09/22/preparing-your-plugins-and-your-client-sites-for-termmeta/\">read this post</a> on how to prepare for the switch. Also, the underlying <a href=\"https://make.wordpress.org/core/2015/09/22/preparing-your-plugins-and-your-client-sites-for-termmeta/\">WP_Term class</a> improves caching when working with terms.</li>\n<li><strong>Improved <code>&lt;title&gt;</code> output</strong> — <code>wp_title()</code> is deprecated; WordPress will <a href=\"https://make.wordpress.org/core/2015/10/20/document-title-in-4-4/\">handle the rendering</a> of the document title automatically.</li>\n<li><strong>Comments </strong>— Comment queries are now split for performance. Also, the underlying <code>WP_Comment</code> class improves caching and introduces strong-typing. (<a href=\"https://core.trac.wordpress.org/ticket/8071\">#8071</a>, <a href=\"https://core.trac.wordpress.org/ticket/32619\">#32619</a>)</li>\n</ul>\n<p>Users are highly encouraged to test WordPress 4.4 and report bugs to the <a href=\"https://wordpress.org/support/forum/alphabeta\">Alpha/Beta section</a> of the support forums. Remember, the beta is software still in development and therefor not recommend for use on a production site. WordPress 4.4 <a href=\"https://make.wordpress.org/core/version-4-4-project-schedule/\">is scheduled</a> for release on December 8th.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 23 Oct 2015 18:57:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:15;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WPTavern: WPWeekly Episode 210 – Great Scott!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48680\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:52:\"http://wptavern.com/wpweekly-episode-210-great-scott\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2994:\"<p>In this time travel inspired episode of WordPress Weekly, <a href=\"http://marcuscouch.com/\">Marcus Couch</a> and I catch you up on the news of the week. I start the show by sharing my experience attending the first WordCamp Hampton Roads in Virginia Beach, VA. While in Virginia Beach, I visited and worked from the <a href=\"http://www.rocketgenius.com/\">Rocketgenius</a> office and observed how the team behind Gravity Forms works on a daily basis. In the show, I explain why I think the company&#8217;s setup is the best of both worlds for distributed workers.</p>\n<p>We discuss what the future of WordPress may be like 10 years from now and whether or not it&#8217;s time for the XML-RPC protocol to be removed from WordPress. We end the show with the plugin picks of the week.</p>\n<h2>Stories Discussed:</h2>\n<p><a href=\"http://wptavern.com/anyssa-ferreira-awarded-the-kim-parsell-memorial-scholarship\">Anyssa Ferreira Awarded the Kim Parsell Memorial Scholarship</a><br />\n<a href=\"https://make.wordpress.org/core/2015/10/20/document-title-in-4-4/\">WP_Title is deprecated in WordPress 4.4</a><br />\n<a href=\"http://torquemag.io/what-will-wordpress-be-like-in-next-10-years/\">What Will WordPress Be Like In Next 10 Years?</a> Here’s an <a href=\"http://torquemag.io/what-will-wordpress-be-like-in-next-10-years/#comment-2299329174\">awesome comment</a> on the article.<br />\n<a href=\"http://wptavern.com/its-time-for-xml-rpc-in-wordpress-to-hit-the-road\">It’s Time for XML-RPC in WordPress to Hit the Road</a></p>\n<h2>Plugins Picked By Marcus:</h2>\n<p><a href=\"https://wordpress.org/plugins/woo-price-per-word/\">WooCommerce Price Per Word</a> allows customers to upload a document to the product page. The word-count of the document is used to calculate the price based on the price-per-word entered for the product.</p>\n<p><a href=\"https://wordpress.org/plugins/shortcode-tester/\">Shortcode Tester</a> is a post editor tool for WordPress developers that displays the HTML generated by WordPress shortcodes in a popup window. You can quickly view the generated HTML without having to view the entire post.</p>\n<p><a href=\"https://wordpress.org/plugins/beehive/\">Beehive cells</a> arranges the content on your front page into a series of hexagonal cells similar to a beehive.</p>\n<h2>WPWeekly Meta:</h2>\n<p><strong>Next Episode:</strong> Wednesday, October 28th 9:30 P.M. Eastern</p>\n<p><strong>Subscribe To WPWeekly Via Itunes: </strong><a href=\"https://itunes.apple.com/us/podcast/wordpress-weekly/id694849738\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via RSS: </strong><a href=\"http://www.wptavern.com/feed/podcast\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via Stitcher Radio: </strong><a href=\"http://www.stitcher.com/podcast/wordpress-weekly-podcast?refid=stpr\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Listen To Episode #210:</strong><br />\n</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 22 Oct 2015 09:06:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:16;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"WPTavern: WordPress 4.4 to Deprecate the wp_title Function\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48669\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"http://wptavern.com/wordpress-4-4-to-deprecate-the-wp_title-function\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1711:\"<p>A year after <a href=\"https://make.wordpress.org/core/2014/10/29/title-tags-in-4-1/\">WordPress 4.1 introduced</a> a new way to display titles in themes, WordPress 4.4 <a href=\"https://make.wordpress.org/core/2015/10/20/document-title-in-4-4/\">will deprecate</a> <code>wp_title()</code>. With <a href=\"https://core.trac.wordpress.org/changeset/35294\">the change</a>, plugin authors will be able to check for theme support and use a few new filters to manipulate the title. The new filters are as follows:</p>\n<ul>\n<li><code>\'pre_get_document_title\'</code> short-circuits <code>wp_get_document_title()</code> if it returns anything other than an empty value.</li>\n<li><code>\'document_title_separator\'</code> filters the separator between title parts.</li>\n<li><code>\'document_title_parts\'</code> filters the parts that make up the document title, passed in an associative array.</li>\n</ul>\n<p>Theme authors should no longer use <code>wp_title()</code> to generate document titles. If theme authors add <code>add_theme_support( ‘title-tag’ );</code> to the <code>after_setup_theme</code> callback, the title will be handled natively via an internal WordPress core function. If you use a theme that utilizes wp_title and have <a href=\"https://codex.wordpress.org/WP_DEBUG\">wp_debug enabled</a> in WordPress 4.4, you&#8217;ll see a deprecation notice.</p>\n<p>In general, users who upgrade to WordPress 4.4 won&#8217;t notice a difference. However, with nearly a <a href=\"https://make.wordpress.org/core/version-4-4-project-schedule/\">month to go</a> before WordPress 4.4 is released, theme developers are highly encouraged to check and update their themes accordingly.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 22 Oct 2015 07:52:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:17;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"WPTavern: Anyssa Ferreira Awarded the Kim Parsell Memorial Scholarship\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48662\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"http://wptavern.com/anyssa-ferreira-awarded-the-kim-parsell-memorial-scholarship\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2542:\"<p>Back in August, the WordPress Foundation <a href=\"http://wptavern.com/the-wordpress-foundation-begins-accepting-applications-for-the-kim-parsell-memorial-scholarship\">began accepting applications</a> for the <a href=\"http://wptavern.com/the-wordpress-foundation-creates-a-traveling-scholarship-in-memory-of-kim-parsell\">Kim Parsell Memorial Scholarship</a>. The scholarship not only serves as a memorial, but gives one woman in the WordPress community an opportunity to attend WordCamp US with financial assistance from the foundation.</p>\n<p><a href=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/AnyssaFerreira.jpg\"><img class=\"wp-image-48664 size-full\" src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/AnyssaFerreira.jpg?resize=256%2C256\" alt=\"AnyssaFerreira\" /></a>Anyssa FerreiraThe WordCamp US website <a href=\"https://2015.us.wordcamp.org/2015/10/14/announcing-the-kim-parsell-memorial-scholarship-winner-anyssa-ferreira/\">announced</a> Anyssa Ferreira, a Brazilian designer, feminist, and WordPress community activist as the first recipient of the scholarship. Ferreira organized and spoke at WordCamp São Paulo in 2014 and designed the event&#8217;s website. She was the only woman to speak and volunteer at the event.</p>\n<p>In 2015, Ferreira spoke at WordCamp Belo Horizonte&nbsp;on women working with WordPress in the Brazilian community. According to the post, Ferreira continues to play an active role encouraging women to get involved with WordPress and the technology field in Brazil:</p>\n<blockquote><p>She has worked to debunk the myth that women have no interest in WordPress and web development. She has explored why women were not participating, speaking personally with many female programmers, designers and other WordPress professionals about this important topic. She regularly invites women to attend her local WordPress meetup, and works to ensure that they feel welcome and wanted when they do attend.</p></blockquote>\n<p>Not only does Ferreira fulfill the <a href=\"http://wptavern.com/the-wordpress-foundation-begins-accepting-applications-for-the-kim-parsell-memorial-scholarship\">scholarship&#8217;s requirements</a>, she&#8217;s the type of woman Kim Parsell would love to meet and talk to in person.</p>\n<p>Thanks again to Jen Mylo, the WordPress foundation, and Matt Mullenweg for not only creating the scholarship, but for providing an opportunity for people like Ferreira to experience the largest annual WordPress conference first-hand.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 21 Oct 2015 23:00:22 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:18;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"WPTavern: It’s Time for XML-RPC in WordPress to Hit the Road\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48643\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"http://wptavern.com/its-time-for-xml-rpc-in-wordpress-to-hit-the-road\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:8672:\"<hr />\n<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/JesseNicklesAvatar.jpg\"><img class=\"alignright wp-image-48651 size-thumbnail\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/JesseNicklesAvatar.jpg?resize=150%2C150\" alt=\"Jesse Nickles Founder of Little Bizzy\" /></a>This post was contributed by <a href=\"https://www.linkedin.com/pub/jesse-nickles/61/807/435\" target=\"_blank\">Jesse Nickles</a>. He is the founder of <a href=\"https://www.littlebizzy.com\" target=\"_blank\">LittleBizzy</a>, a managed WordPress hosting company, and a part-time blogger at <a href=\"https://collegetimes.co/\" target=\"_blank\">CollegeTimes</a>, where he gets into trouble exploring controversial issues.</p>\n<hr />\n<p>Two weeks ago, I <a href=\"https://www.littlebizzy.com/blog/disable-xml-rpc\">announced</a> that all current and future domains hosted at <a href=\"https://www.littlebizzy.com\" target=\"_blank\">LittleBizzy</a> would have <a href=\"https://codex.wordpress.org/XML-RPC_Support\" target=\"_blank\">XML-RPC</a> permanently blocked due to the non-stop problems it was causing. In the announcement, we recommended that other WordPress users across the globe urgently consider blocking the technology on their own web servers as well.</p>\n<h2>XML-RPC in WordPress Has a Troubled Past</h2>\n<p>Days after the announcement<em>,</em> Daniel Cid, founder and CTO of Sucuri, and Mark Maunder, CEO of WordFence, <a href=\"https://blog.sucuri.net/2015/10/brute-force-amplification-attacks-against-wordpress-xmlrpc.html\" target=\"_blank\">confirmed</a> the <a href=\"https://www.wordfence.com/blog/2015/10/wordpress-xml-rpc-brute-force-attacks-amplification-multiple-logins/\" target=\"_blank\">reports</a> that a new type of Brute Force login attack was being carried out on a massive scale against WordPress sites around the world using XML-RPC. Apparently, hackers have wised up to the fact that <code>wp-login.php</code> is often well protected.</p>\n<p>Perhaps more shocking than this latest wave of attacks is that <em>they are nothing new,</em> as Sucuri previously <a href=\"https://blog.sucuri.net/2014/07/new-brute-force-attacks-exploiting-xmlrpc-in-wordpress.html\">reported a similar wave of attacks</a> in July 2014. Let&#8217;s also not forget the wide-scale use of XML-RPC to perform <a href=\"http://www.webopedia.com/TERM/D/DDoS_attack.html\">DDoS attacks</a> on WordPress websites <a href=\"https://www.incapsula.com/blog/wordpress-security-alert-pingback-ddos.html\">reported by Incapsula</a> in 2013. Combine these reports with <a href=\"https://www.google.com/search?hl=en&q=site%3Awordpress.org%2Fsupport%2F+xml-rpc+attack\">hundreds of posts</a> on the wordpress.org support forums and <a href=\"https://www.google.com/search?hl=en&q=site%3Astackoverflow.com+xml-rpc+attack\">Stack Overflow</a> and a picture is painted of years of unhindered attacks against millions of WordPress sites due to this single PHP file, yikes!</p>\n<blockquote><p>It is common sense to take a method and try it. If it fails, admit it frankly and try another. But above all, try something. ― Franklin D. Roosevelt</p></blockquote>\n<p>I didn&#8217;t expect to be the one to advocate that XML-RPC be removed from WordPress but that&#8217;s exactly what I&#8217;m doing: <strong>It&#8217;s time for WordPress XML-RPC to hit the road, for good.</strong></p>\n<h2>XML-RPC Was a Conscious Mistake</h2>\n<p>I understand that thousands of volunteer hours have been invested into XML-RPC support for the WordPress platform, as is the nature of open-source communities. I sincerely respect and thank said programmers and volunteers for creating a very cool way to remotely connect to a website built on WordPress. But sometimes, we need to be honest with ourselves and admit when something isn&#8217;t working; <em>This one of those times.</em></p>\n<p>If you&#8217;re wondering why I&#8217;m framing the XML-RPC mess as a conscious mistake, <strong>that&#8217;s because it was</strong>. Three years ago, Andrew Nacin, a WordPress core developer, <a href=\"https://core.trac.wordpress.org/ticket/21509\" target=\"_blank\">announced</a> in a trac ticket that, <em>&#8220;Security is no greater a concern than the rest of core. There is no longer a compelling reason to disable [XML-RPC] by default. It’s time we should remove the option entirely.&#8221;</em></p>\n<p>Three years later, millions of WordPress sites have been hacked, crashed, or attacked, due to XML-RPC. It’s undeniable that removing the option to disable it (and/or enabling it by default) was wrong.</p>\n<h2>Out of Touch With the Average User</h2>\n<p>When broken down, it&#8217;s a classic case of extremely talented and intelligent software developers being out of touch with the millions of <strong>average Joes</strong> that use WordPress and have no idea what XML-RPC is. When developers inevitably argue that there are several free security plugins available that can help combat XML-RPC attacks, they completely miss the point: <u>the majority of webmasters being attacked are the same ones who don&#8217;t even know what a security plugin is or how to use it</u>.</p>\n<p>Ironically, the one good <a href=\"https://wordpress.org/plugins/bruteprotect/\" target=\"_blank\">standalone plugin</a> that fought Brute Force login attempts was <a href=\"http://wptavern.com/automattic-acquires-parka-llc-the-creators-of-bruteprotect\" target=\"_blank\">foolishly</a> <a href=\"http://wptavern.com/jetpack-protect-blocks-brute-force-amplification-attacks\" target=\"_blank\">combined</a> into the controversial Jetpack plugin, which most serious webmasters would never consider installing.</p>\n<p>The premise, of course, for XML-RPC support in WordPress is a noble idea that sounds versatile: it allows, as previously mentioned, remote connections (logins, usually) to any given domain that is running a WordPress installation. In reality, however, this XML-RPC functionality is primarily used for three common reasons:</p>\n<ol>\n<li>Pingbacks/trackbacks (great for Viagra spam, <a href=\"http://wptavern.com/wptavern-was-trackbacked-to-death\" target=\"_blank\">DDoS attacks</a>, and not much else)</li>\n<li>Jetpack (an all-in-one solution to <a href=\"http://blog.arunas.co/project-measure-jetpack/\" target=\"_blank\">slowing down</a> and/or bloating your WordPress site with third-party scripts)</li>\n<li>WP mobile apps (I&#8217;m not sure who blogs from their smart phone, but the <a href=\"https://itunes.apple.com/us/app/yo./id834335592\" target=\"_blank\">YO app</a> is literally rated higher than <a href=\"https://itunes.apple.com/en/app/wordpress/id335703880\" target=\"_blank\">WordPress</a> on the iTunes store, and the user reviews of the <a href=\"https://play.google.com/store/apps/details?id=org.wordpress.android\" target=\"_blank\">Android</a> version repeatedly point to XML-RPC login issues)</li>\n</ol>\n<p>Do recall that the WordPress backend is now responsive, which means you can login to your blog from practically any mobile device; this wasn’t the case when the native WordPress mobile apps were first launched. And arguably, the vast majority of WordPress sites have absolutely no use for pingbacks, trackbacks, or XML-RPC in general.</p>\n<h2>XML-RPC Needs to Be Disabled or Removed From WordPress</h2>\n<p><u>The logical conclusion should be immediately clear:</u> XML-RPC needs to die a quick death in the WordPress community, or at least be shifted into an optional (non-default) plugin or otherwise, in order to bring an immediate and measurable improvement to the security and stability of not only WordPress sites, but the internet overall.</p>\n<p>Perhaps Jeff Chandler <a href=\"http://wptavern.com/how-to-prevent-wordpress-from-participating-in-pingback-denial-of-service-attacks\" target=\"_blank\">said it best</a>:</p>\n<blockquote><p>WP Tavern is no stranger to denial of service attacks due to pingbacks and trackbacks. In 2010, I explained how WP Tavern was trackbacked to death. Shortly after the website came back online, I disabled both as I feared they might end up taking the site down again. A few years have gone by and I’ve re-enabled pingbacks and trackbacks with no ill effects. However, I wonder if it’s time to kill them once and for all, not just on WP Tavern but in WordPress in general.</p></blockquote>\n<p>Sometimes, we as developers and others with a technical mindset get caught up in solving the challenge of the day, when what is really needed is to step back and take a more philosophical look at the bigger picture. Is this thing worth our time, or is it causing more problems than solutions? When it comes to XML-RPC in WordPress, the conclusion is obvious.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 21 Oct 2015 21:33:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:19;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"Post Status: Playing with type\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://poststatus.com/?p=14750\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"https://poststatus.com/playing-with-type/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:8443:\"<p>I am far from a typography expert, but I do love playing with type. I delight in a great reading experience, and I strongly believe typography is the key to creating a great reading experience.</p>\n<p>In my own journeys searching for and choosing typefaces for my projects, I&#8217;ve discovered some great tools, and also some pitfalls of using different delivery services.</p>\n<p>I have <a href=\"http://typography.com\">Typography.com</a> and <a href=\"http://typekit.com\">Typekit</a> accounts, and of course using <a href=\"http://google.com/fonts\">Google Fonts</a> is very simple. Many folks also use <a href=\"http://www.myfonts.com/\">Myfonts</a>, generate their own on <a href=\"http://www.fontsquirrel.com/\">Fontsquirrel</a>, self-host direct from foundries, or use a variety of other methods.</p>\n<p>When you use a font delivery service, where the font is hosted elsewhere, and you simply connect (like Typekit or Typography.com), one of the things you deal with is the authentication of your site with the service that can often cause sad delays in pageload times. Zach Tollman did a great post discussing how <a href=\"https://www.tollmanz.com/typography-coms-cssom-blocking-font-loader/\">Typography.com in particular is not good at handling this authentication</a>, from a performance perspective.</p>\n<p>Given that I host Post Status fonts on Typography.com &#8212; I use Gotham Round, Gotham Condensed, and Sentinel here, and none of them are available anywhere else &#8212; the hit on performance perturbs me. However, I love these fonts and hate to replace them. However, I&#8217;ve lately been doing some research so I can at least test font stacks from Typekit and Google to see how big of an impact it could have.</p>\n<h3>Finding Typefaces</h3>\n<p>Finding quality typefaces is a challenge. There are <em>so many</em> out there, and the differences in quality can be vast. Part of what I love about Typography.com is that the quality of the display and cross-browser rendering is outstanding. Typekit serves typefaces from a variety of foundries, but they too have built great tools over the years to try and ensure quality rendering. Google is more of a mixed bag, though open source typefaces are getting more attention to detail in recent years than ever before.</p>\n<p>By far, my favorite tool for browsing and finding typefaces is <a href=\"https://www.typewolf.com\">Typewolf</a>. Typewolf has PDF guides (free with your email), trending typefaces, sites of the day, and high quality recommendations on when and where to use a particular typeface. A sample resource that&#8217;s outstanding is their list of the <a href=\"https://www.typewolf.com/open-source-web-fonts\">top 30 open source Google fonts</a>. They have many others like that. It&#8217;s definitely a must-visit site when you are considering changing up your site typography.</p>\n<p>You can also browse delivery services directly. Typekit&#8217;s <a href=\"https://typekit.com/lists\">lists</a> are pretty good for narrowing typefaces by their intended purpose. <a href=\"http://justmytype.co/\">Justmytype</a> is another great resource that shows recommended pairings for fonts from Typekit and Typography.com. And of course Google has filters in their directory to help narrow it down, but it&#8217;s still a bit of the wild west, so I usually rely on Googling good pairings for Google.</p>\n<h3>Tinkering with typefaces with real content</h3>\n<p>Once you find some Typefaces you like, then it&#8217;s fun to put them into practice. <a href=\"http://typecast.com/\">Typecast</a> is excellent. You can find fonts from many foundries with a free account, and do all sorts of manipulations to see the typefaces in action, using a variety of font combinations, before you move to your actual site.</p>\n<p><img class=\"aligncenter size-large wp-image-14749\" src=\"https://cdn.poststatus.com/wp-content/uploads/2015/10/typecast-view-752x462.png\" alt=\"typecast-view\" width=\"752\" height=\"462\" /></p>\n<p>Beware, it&#8217;s easy to spend hours in this tool. I love that you can edit the CSS directly, and there are also tools within Typecast to insert particular types of content, so you can have a working prototype pretty quickly.</p>\n<h3>Performance implications</h3>\n<p>Loading fonts is a huge performance issue sometimes. Too many fonts, content blocking loading, time-outs from third party delivery services, and other gotchas can severely impact a site&#8217;s load times.</p>\n<p>Anytime you are looking at new typefaces to use, consider where you can serve them from, whether you can self host them, how the delivery authenticates, and potentially more &#8212; before you get your heart set.</p>\n<p>Some good rules of thumb are this:</p>\n<ul>\n<li>Google is by far the fastest, but you just don&#8217;t have access to some of the greatest font foundries this way, because all Google fonts are free.</li>\n<li>Self hosting is probably similar to or faster than serving them from Google. Most Google fonts are locally cached on lots of folks computers. Self hosting may be better for a more rare font, but for common fonts, Google may actually be faster.</li>\n<li>System fonts are always the fastest, but you might not be able to deliver your preferred typeface if the system the reader is using doesn&#8217;t support the typeface. If using system typefaces, creating thorough font stacks is a necessity. Sometimes, especially for sans-serifs, I&#8217;m tempted to just declare sans-serif, so that the system serves its favorite font &#8212; as Android, Mac, iOS, Windows, et al each have their own defaults. For serifs, I&#8217;d say just use Georgia if using system fonts only <img src=\"https://cdn.poststatus.com/wp-includes/images/smilies/simple-smile.png\" alt=\":)\" class=\"wp-smiley\" /></li>\n<li>Typekit and Myfonts and other delivery services are usually similar in quality, but it&#8217;s one of the slowest options for delivery. Be sure to only use the weights and versions you need, and considering limiting character sets if you can get away with it.</li>\n<li>Have a performance budget for your type. Sometimes you have to make hard choices. Does your body font really need to be a non-system font? What if you just used a single display font to add the character you seek? Can you get away without italics for a certain typeface you&#8217;re using? What about bold? If you use the regular/bold/italic/bold-italic for every typeface, that adds up quickly. Use the bare minimum and add whenever you need to only.</li>\n</ul>\n<h3>Don&#8217;t get too fancy, and consider your tone</h3>\n<p>My biggest mistakes over the years playing with type have been getting too fancy, especially with body copy. Simple is good with type. Especially when choosing body copy, be sure to learn about the typeface you like &#8212; and don&#8217;t just trust your own eye early on &#8212; to see if it&#8217;s an appropriate workhorse typeface.</p>\n<p>With display type, you have more leeway, but consider the mood that the typeface sets. Slabs, serifs, gothic, humanist, and other styles of type each tend to have their own tone that they set. For instance, when you read the New York Times, Georgia is a serious workhorse font, and the custom display font also sets a sober tone. Compared to Vox, for example, which uses a more casual sans-serif body copy and quite decorative display typeface. In both scenarios, readability is very good, but they set a different tone.</p>\n<h3>Learning typography takes time</h3>\n<p>Learning and understanding good typography practices takes time. Many factors are at play to make a typeface look great, and even the greatest typefaces can get screwed up when not used well.</p>\n<p>Learning best practices for things like line length, line height, pairing, and much much more can probably get you farther than what typeface you choose. And different typefaces obviously do better in different settings. The key is to take it slow, learn what you like when you are reading other websites, and see what they are doing that you are not. Also, ask your friends about your choices and get feedback; sometimes just a minor change can make a big difference, and suddenly your design clicks.</p>\n<p>We can easily be blind to our own typography mistakes. If you can limit mistakes and learn the essentials of choosing typefaces and using them well, your websites will look much, much better and your readers will be thankful, even if they never say it.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 16 Oct 2015 17:23:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Brian Krogsgard\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:20;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"Post Status: Work life balance — Draft podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://poststatus.com/?p=14740\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"https://poststatus.com/work-life-balance-draft-podcast/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1393:\"<p>Welcome to the Post Status Draft podcast, which you can find <a href=\"https://itunes.apple.com/us/podcast/post-status-draft-wordpress/id976403008\">on iTunes</a> and <a href=\"http://simplecast.fm/podcasts/1061/rss\">via RSS</a> for your favorite podcatcher. Brian and his co-host, <a href=\"https://twitter.com/joe_hoyle\">Joe Hoyle</a>, a co-founder and the CTO of <a href=\"https://hmn.md/\">Human Made</a>, discuss some of today’s hottest, current WordPress news.</p>\n<p>In this episode of Draft, Joe and Brian discuss work life balance. We discuss working long hours, managing and preventing burnout, moonlighting and its challenges, side projects, embracing hobbies, and creating exercise routines.</p>\n<a href=\"https://audio.simplecast.fm/18534.mp3\">https://audio.simplecast.fm/18534.mp3</a>\n<p><a href=\"http://audio.simplecast.fm/18534.mp3\">Direct Download</a></p>\n<p>Links</p>\n<ul>\n<li><a href=\"http://www.carriedils.com/overcoming-burnout/\">Overcoming burnout</a></li>\n<li><a href=\"http://dangerousminds.net/comments/photographer_removes_smartphones_from_images_to_show_how_obsessed_we_are_wi\">People without phones in phone poses</a></li>\n<li><a href=\"http://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html\">Epic procrastination series</a></li>\n<li><a href=\"http://andyadams.org/why-you-shouldnt-moonlight/\">Don&#8217;t moonlight long-term</a></li>\n</ul>\n<p>&nbsp;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 16 Oct 2015 13:24:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Katie Richards\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:21;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"WPTavern: Akismet 3.1.5 Fixes Critical XSS Security Vulnerability\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48619\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"http://wptavern.com/akismet-3-1-5-fixes-critical-xss-security-vulnerability\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1629:\"<p>If you use <a href=\"https://wordpress.org/plugins/akismet/\">Akismet</a> to battle comment spam, make sure it&#8217;s running version 3.1.5 as it patches a critical security vulnerability. Due to the nature of the bug, the Akismet team pushed out auto updates to sites that can accept them. According <a href=\"https://blog.sucuri.net/2015/10/security-advisory-stored-xss-in-akismet-wordpress-plugin.html\">to Sucuri</a>, sites using Akismet 3.1.4 and lower and that have the <strong><em>Convert emoticons like <img class=\"wp-smiley\" src=\"https://blog.sucuri.net/wp-includes/images/smilies/simple-smile.png\" alt=\":-)\" /> and <img src=\"http://s.w.org/images/core/emoji/72x72/1f61b.png\" alt=\"?\" class=\"wp-smiley\" /> to graphics on display</em></strong> option enabled, are at risk.</p>\n<p>The vulnerability stems from the way Akismet handles hyperlinks within a site&#8217;s comments. An attacker with sufficient knowledge of WordPress&#8217; internals could insert malicious scripts in the Comment section of the WordPress backend. This type of attack could lead to a number of other attacks, including compromising an entire site.</p>\n<p>So far, Akismet developers <a href=\"http://blog.akismet.com/2015/10/13/akismet-3-1-5-wordpress/\">don&#8217;t have any evidence</a> that the vulnerability is actively being exploited in the wild. Because the vulnerability is theoretically exploitable via comments, Akismet is blocking attempts during the comment-check API call so that sites not running the most recent version are protected. However, you should still upgrade immediately to 3.1.5.</p>\n<div id=\"epoch-width-sniffer\"></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 15 Oct 2015 20:08:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:22;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"Matt: Working &amp; Exercising\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45486\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"http://ma.tt/2015/10/working-exercising/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1653:\"<p><img class=\"  wp-image-45499 aligncenter\" src=\"http://i1.wp.com/ma.tt/files/2015/10/IMG_3075.jpg?w=604\" /></p>\n<p>One benefit of working from home that doesn&#8217;t get discussed much is the ease of small, but frequent exercise activities through the day. I&#8217;m sure it&#8217;s not outlawed in an office to get out of your chair and do 20 jumping jacks, or plank for a minute, I definitely would feel awkward doing so. This is something on my mind as I&#8217;m working this week around ~400 colleagues for <a href=\"https://twitter.com/hashtag/a8cgm\">our once-a-year Grand Meetup</a>.</p>\n<p>When I&#8217;m home and have a ton of work to get through, my favorite approach is the <a href=\"https://en.wikipedia.org/wiki/Pomodoro_Technique\">Pomodoro Technique</a> with 25 minutes on followed by a 5 minute break. (<a href=\"https://itunes.apple.com/us/app/pomodoro-one/id907364780?mt=12\">I use this app</a> but any timer will do.) The 5 minute break is a fantastic time to do something small, like a few push-ups, squats, a plank, or even meditate. (The new <a href=\"https://itunes.apple.com/us/app/pause-relaxation-at-your-fingertip/id991764216?mt=8\">Pause app is cool</a>, and of course I <a href=\"http://calm.com/\">love Calm</a>.) You don&#8217;t have to do a ton, but over the course of a day or a week these 5 minute break exercises add up to be quite a bit and can <a href=\"http://tinyhabits.com/\">kickstart a Tiny Habit</a>. And don&#8217;t even get me started on the benefits of naps.</p>\n<p>Again, not something that&#8217;s impossible in an shared office, just feels a lot more natural and less embarrassing in your private home office.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 14 Oct 2015 18:37:30 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:23;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"Akismet: Akismet 3.1.5: Security Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"http://blog.akismet.com/?p=1877\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"http://blog.akismet.com/2015/10/13/akismet-3-1-5-wordpress/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1660:\"<p><b>Version 3.1.5 of the Akismet plugin for WordPress contains a critical security fix. Update your sites as soon as possible.</b></p>\n<p>A researcher from <a href=\"https://sucuri.net/\">Sucuri</a> notified us of an XSS vulnerability in the Akismet WordPress plugin. This bug affects all versions of the Akismet WordPress plugin since 2.5.0, but we have no evidence that it has been exploited in the wild.</p>\n<p>We&#8217;ve released updates for all vulnerable versions of the Akismet plugin. Additionally, the WordPress.org plugins team has enabled an <a href=\"https://make.wordpress.org/plugins/2015/03/14/plugin-automatic-security-updates/\">automatic update</a> for all sites running these vulnerable versions that are able to auto-update plugins.</p>\n<p>Because the vulnerability is theoretically exploitable via comments, Akismet is already blocking attempts during the comment-check API call even if you are not running the most recent version. However, to be as safe as possible, you should still upgrade immediately.</p>\n<p>To upgrade, visit the Updates page of your WordPress dashboard and follow the instructions. If you need to download the plugin zip file directly, links to all versions are available in <a href=\"http://wordpress.org/plugins/akismet/\">the WordPress plugins directory</a>.</p><br />  <a rel=\"nofollow\" href=\"http://feeds.wordpress.com/1.0/gocomments/akismet.wordpress.com/1877/\"><img alt=\"\" border=\"0\" src=\"http://feeds.wordpress.com/1.0/comments/akismet.wordpress.com/1877/\" /></a> <img alt=\"\" border=\"0\" src=\"http://pixel.wp.com/b.gif?host=blog.akismet.com&blog=116920&post=1877&subd=akismet&ref=&feed=1\" width=\"1\" height=\"1\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 13 Oct 2015 20:37:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Xopher Finke\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:24;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"WPTavern: Jetpack Protect Blocks Brute Force Amplification Attacks\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48601\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"http://wptavern.com/jetpack-protect-blocks-brute-force-amplification-attacks\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2469:\"<p>If you&#8217;ve noticed an influx of brute force attacks on your site, you&#8217;re not the only one. Sucuri <a href=\"https://blog.sucuri.net/2015/10/brute-force-amplification-attacks-against-wordpress-xmlrpc.html\">is reporting</a> that brute force amplification attacks are targeting WordPress sites with XML-RPC enabled. In a nutshell, XML-RPC contains a system.multicall method which allows developers to execute multiple methods and commands inside a single request.</p>\n<h2>What is a Brute Force Amplification Attack?</h2>\n<p>In a typical brute force attack, several machines or bots try to guess the username and password for a site one  at a time. In a brute force amplification attack, attackers can guess hundreds or thousands of combinations within a single request making the attack more efficient and difficult to block.</p>\n<p>The XML-RPC protocol in WordPress is a communications bridge between remote applications such as the WordPress mobile apps and the site itself. It&#8217;s also used to communicate and authenticate to Jetpack.</p>\n<h2>Jetpack Protect Does Its Job</h2>\n<p>Jetpack comes with a module called <a href=\"http://jetpack.me/support/security-features/\">Jetpack Protect</a> formerly <a href=\"http://wptavern.com/automattic-acquires-parka-llc-the-creators-of-bruteprotect\">known as BruteProtect</a>, that protects sites from brute force attacks. Sam Hotchkiss, lead developer of Jetpack Protect, <a href=\"https://samhotchkiss.wordpress.com/2015/10/12/testing-for-xml-rpc-multicall-vulnerabilities-in-wordpress/\">confirms in a blog post</a> that Jetpack Protect blocks brute force amplification attacks out-of-the box.</p>\n<blockquote><p>In our testing, we confirmed that Jetpack Protect (and BruteProtect) do block this attack vector.  If you’re running Jetpack with Protect enabled or you’re running BruteProtect, you don’t need to do anything to keep yourself safe from this attack technique.</p></blockquote>\n<p>If you use Jetpack Protect, you don&#8217;t need to do anything to block this attack vector. For everyone else, Sucuri recommends that administrators block system.multicall requests as they&#8217;re not used much in the wild. There&#8217;s also a handful of security plugins such as <a href=\"https://wordpress.org/plugins/better-wp-security/\">iThemes Security</a> or <a href=\"https://wordpress.org/plugins/wp-simple-firewall/\">WordPress Simple Firewall</a> that block system.multicalls and can disable XML-RPC.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 13 Oct 2015 18:24:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:25;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"WPTavern: What Do You Want to See in a WordPress.tv Redesign?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48595\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"http://wptavern.com/what-do-you-want-to-see-in-a-wordpress-tv-redesign\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1693:\"<p>The <a href=\"http://wordpress.tv/\">WordPress.tv</a> team is <a href=\"https://make.wordpress.org/tv/2015/10/08/building-a-better-wordpress-tv-functional-requirements/\">requesting feedback</a> on what features you&#8217;d like to see in a website redesign. Jerry Bates, volunteer moderator for WordPress.tv, says one of the goals for 2016 is to update the site to better showcase content from WordCamps around the world. While plans are underway, the team wants to know what you think of WordPress.tv as it is today and what it would be in a perfect world.</p>\n<p>Oleg Belousov suggests <a href=\"https://make.wordpress.org/tv/2015/10/08/building-a-better-wordpress-tv-functional-requirements/comment-page-1/#comment-1483\">WordPress.TV have a playlist feature</a> so viewers can favorite videos. I&#8217;d also like to see this feature and have the videos saved to my WordPress.org profile. I&#8217;ve noticed that a lot of links to presentation slides point to the speaker&#8217;s personal site. To protect against link rot and expiring domains, WordPress.tv or a sister site should host presentation slides.</p>\n<p>On the single post view for videos, you have to scroll down to read a video&#8217;s description in the right hand sidebar. Instead, I&#8217;d like to see WordPress.tv display information and related videos similar to YouTube since most of the relevant information is near the video itself. The redesign should also be responsive. If you have ideas to improve WordPress.tv or feature requests, please <a href=\"https://make.wordpress.org/tv/2015/10/08/building-a-better-wordpress-tv-functional-requirements/comment-page-1/\">leave a comment</a> on the Make.WordPress.tv site.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 12 Oct 2015 17:02:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:26;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"Matt: HR Meets Science\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45307\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"http://ma.tt/2015/10/hr-meets-science/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:156:\"<p><span class=\"embed-youtube\"></span></p>\n<p>Great talk on analytical HR at Google. <cite>Hat tip: <a href=\"http://whenihavetime.com/\">Sara</a>.</cite></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 11 Oct 2015 18:04:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:27;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"Matt: Super Impressive Mario\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45353\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:44:\"http://ma.tt/2015/10/super-impressive-mario/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:179:\"<p><span class=\"embed-youtube\"></span></p>\n<p>This custom Mario Maker level, and the skill required to beat it, is one of the craziest feats of Mario virtuoso I&#8217;ve seen.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 09 Oct 2015 22:35:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:28;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"Post Status: Responsive images for WordPress and mobile pages with AMP — Draft podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://poststatus.com/?p=14573\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://poststatus.com/responsive-images-for-wordpress-and-mobile-pages-with-amp-draft-podcast/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1740:\"<p>Welcome to the Post Status Draft podcast, which you can find <a href=\"https://itunes.apple.com/us/podcast/post-status-draft-wordpress/id976403008\">on iTunes</a> and <a href=\"http://simplecast.fm/podcasts/1061/rss\">via RSS</a> for your favorite podcatcher. Brian and his co-host, <a href=\"https://twitter.com/joe_hoyle\">Joe Hoyle</a>, a co-founder and the CTO of <a href=\"https://hmn.md/\">Human Made</a>, discuss some of today’s hottest, current WordPress news.</p>\n<p><span>In this episode of Draft, Joe and Brian discuss Google’s AMP project for Accelerated Mobile Page loading, and what it means for WordPress. They also go in-depth on WordPress’s upcoming core support for handling responsive images.</span></p>\n<a href=\"https://audio.simplecast.fm/18240.mp3\">https://audio.simplecast.fm/18240.mp3</a>\n<p><a href=\"http://audio.simplecast.fm/18240.mp3\">Direct Download</a></p>\n<h3>Topics &amp; Links</h3>\n<p>Google&#8217;s AMP</p>\n<ul>\n<li><a href=\"https://www.ampproject.org/\">AMP</a></li>\n<li><a href=\"https://www.ampproject.org/how-it-works/\">How AMP works</a></li>\n<li><a href=\"https://vip.wordpress.com/2015/10/07/mobile-web/\">WordPress AMP plugin</a></li>\n<li><a href=\"http://www.niemanlab.org/2015/10/get-ampd-heres-what-publishers-need-to-know-about-googles-new-plan-to-speed-up-your-website/\">AMP on Neiman Lab: What publishers need to know</a></li>\n</ul>\n<p>Responsive Images (starts at 35 minutes in)</p>\n<ul>\n<li><a href=\"https://core.trac.wordpress.org/ticket/33641\">Responsive images merge</a></li>\n<li><a href=\"https://make.wordpress.org/core/2015/09/30/responsive-images-merge-proposal/\">Merge Proposal</a></li>\n<li><a href=\"https://wordpress.org/plugins/ricg-responsive-images/\">Plugin version</a></li>\n</ul>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 09 Oct 2015 18:18:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Katie Richards\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:29;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: Lists of Lists\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45468\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:36:\"http://ma.tt/2015/10/lists-of-lists/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:738:\"<blockquote><p>The app that changed my life is <a href=\"http://simplenote.com/\">Simplenote</a>, linked to Notational Velocity. I have Simplenote on my phone and Notational Velocity on my computer, and I&#8217;m obsessed with to-do lists and lists about my to-do lists. It allows me to have my lists on my phone and my lists on my computer, and they sync&#8230; if you are a list freak, with lists of lists, it will change your life.</p>\n<p>&#8212; Lena Dunham</p></blockquote>\n<p>From a talk with Kara Swisher on Re/code. <a href=\"http://recode.net/podcast-player/216027/\" target=\"_blank\">Listen to the whole podcast</a>, Simplenote comes up at the 48-minute mark. <cite>Hat tip: <a href=\"http://toni.org/\">Toni Schneider</a>.</cite></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 08 Oct 2015 20:13:34 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:30;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"WPTavern: The First Half of the REST API Is Officially Added to WordPress Core\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48563\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"http://wptavern.com/the-first-half-of-the-rest-api-is-officially-added-to-wordpress-core\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2644:\"<p>A few hours ago, Ryan McCue, one of the lead developers of the WordPress REST API project who recently received <a href=\"https://make.wordpress.org/core/2015/10/07/%f0%9f%8e%89-one-more-committer-for-4-4/\">guest commit access</a> for WordPress 4.4, committed <a href=\"https://core.trac.wordpress.org/changeset/34928\">a patch</a> that adds the REST API infrastructure to WordPress core.</p>\n<p>In his commit message, McCue referred to the infrastructure as a baby API:</p>\n<blockquote><p>REST API: Introduce baby API to the world.</p>\n<p>Baby API was born at 2.8KLOC on October 8th at 2:30 UTC. API has lots<br />\nof growing to do, so wish it the best of luck.</p>\n<p>Thanks to everyone who helped along the way:</p>\n<p>Props rmccue, rachelbaker, danielbachhuber, joehoyle, drewapicture, adamsilverstein, netweb, tlovett1, shelob9, kadamwhite, pento, westonruter, nikv, tobych, redsweater, alecuf, pollyplummer, hurtige, bpetty, oso96_2000, ericlewis, wonderboymusic, joshkadis, mordauk, jdgrimes, johnbillion, jeremyfelt, thiago-negri, jdolan, pkevan, iseulde, thenbrent, maxcutler, kwight, markoheijnen, phh, natewr, jjeaton, shprink, mattheu, quasel, jmusal, codebykat, hubdotcom, tapsboy, QWp6t, pushred, jaredcobb, justinsainton, japh, matrixik, jorbin, frozzare, codfish, michael-arestad, kellbot, ironpaperweight, simonlampen, alisspers, eliorivero, davidbhayes, JohnDittmar, dimadin, traversal, cmmarslender, Toddses, kokarn, welcher, and ericpedia.</p></blockquote>\n<p>If you&#8217;re not familiar with the REST API and its potential impacts on WordPress&#8217; future, I highly recommend reading the following articles.</p>\n<ul>\n<li><a href=\"http://wptavern.com/excellent-primer-on-the-wordpress-rest-api-project\">Excellent Primer on the WordPress REST API Project</a></li>\n<li><a href=\"https://poststatus.com/wordpress-json-rest-api/\">The WordPress REST API by Brian Krogsgard</a></li>\n<li><a href=\"http://wptavern.com/ryan-mccue-on-creating-the-json-rest-api-for-wordpress\">Ryan McCue on Creating The JSON REST API for WordPress</a></li>\n<li><a href=\"http://torquemag.io/the-ultimate-guide-to-the-wordpress-rest-api-an-ebook-by-josh-pollock/\">‘The Ultimate Guide To The WordPress REST API,’ An Ebook By Josh Pollock</a></li>\n</ul>\n<p>In the lifespan of an open source project, there are milestone moments. Even though only half of the REST API is in WordPress 4.4, I consider this to be one of those moments.</p>\n<p>If all goes well, developers will have access to the complete REST API in WordPress 4.5. I hope you&#8217;ll join me in congratulating all of the contributors that have and continue to work on the REST API.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 08 Oct 2015 08:38:07 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:31;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"WPTavern: WPWeekly Episode 209 – Where Is the Word Press?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48566\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"http://wptavern.com/wpweekly-episode-209-where-is-the-word-press\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2568:\"<p>In this episode of WordPress Weekly, <a href=\"http://marcuscouch.com/\">Marcus Couch</a> and I are joined by <a href=\"http://werdswords.com/\">Drew Jaynes</a>, WordPress core contributor. We discuss a wide range of topics, from Jaynes&#8217; opinions on Scott Taylor&#8217;s work on WordPress 4.4 thus far to his trip to <a href=\"https://capetown.wordcamp.org/2015/\">WordCamp Capetown Africa, 2015</a>.</p>\n<p>We go in-depth on 10up&#8217;s investments in WordPress and discuss what&#8217;s happened to the Word Press. Last but not least, we discuss why <a href=\"https://twitter.com/jjj/status/647265586624512001\">developers are so excited</a> for Taxonomy Term Meta to be part of WordPress 4.4.</p>\n<h2>Stories Discussed:</h2>\n<p><a href=\"http://wptavern.com/wp101-founded-by-shawn-hesketh-turns-7-years-old\">WP101 Founded by Shawn Hesketh Turns 7 Years Old</a><br />\n<a href=\"http://wptavern.com/the-top-100-active-wordpress-themes-and-plugins-on-godaddys-hosting-network\">The Top 100 Active WordPress Themes and Plugins on GoDaddy’s Hosting Network</a><br />\n<a href=\"http://wptavern.com/6-wordpress-plugins-that-take-native-comments-to-the-next-level\">6 WordPress Plugins That Take Native Comments to the Next Level</a></p>\n<h2>Plugins Picked By Marcus:</h2>\n<p><a href=\"https://wordpress.org/plugins/wp-like-dislike/\">WP Like/Dislike</a> allows visitors to like or dislike a post on your website.</p>\n<p><a href=\"https://wordpress.org/plugins/dorzki-notifications-to-slack/\">Slack Notifications</a> is a plugin that notifies you in your Slack channel via the Slack API on the following: New WordPress Version, New Plugins Updates, Post Published, New User Registration, Admin Login.</p>\n<p><a href=\"https://wordpress.org/plugins/postmatic-for-gravity-forms/\">Postmatic for Gravity Forms</a> is a simple plugin that allows individuals to subscribe to Postmatic feeds using Gravity Forms.</p>\n<h2>WPWeekly Meta:</h2>\n<p><strong>Next Episode:</strong> Wednesday, October 21st 9:30 P.M. Eastern</p>\n<p><strong>Subscribe To WPWeekly Via Itunes: </strong><a href=\"https://itunes.apple.com/us/podcast/wordpress-weekly/id694849738\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via RSS: </strong><a href=\"http://www.wptavern.com/feed/podcast\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via Stitcher Radio: </strong><a href=\"http://www.stitcher.com/podcast/wordpress-weekly-podcast?refid=stpr\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Listen To Episode #209:</strong><br />\n</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 08 Oct 2015 08:32:46 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:32;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"WPTavern: How to Favorite Themes on the WordPress Theme Directory\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48549\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"http://wptavern.com/how-to-favorite-themes-on-the-wordpress-theme-directory\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2145:\"<p>When the WordPress theme directory was <a href=\"http://wptavern.com/wordpress-theme-directory-launches-new-design\">redesigned earlier this year</a>, a <a href=\"http://wptavern.com/wordpress-theme-directory-launches-new-design#comment-65119\">common request from readers</a> was the ability to favorite themes as you can with plugins. This feature was also <a href=\"https://meta.trac.wordpress.org/ticket/28\">suggested</a> by Mario Pesehv two years ago.</p>\n<p>On July 22nd, Dion Hulse <a href=\"https://meta.trac.wordpress.org/changeset/1770\">committed a change</a> with little fanfare to the WordPress theme directory that allows registered users to mark themes as favorites.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/ThemeFavoriteIcon.png\"><img class=\"size-full wp-image-48551\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/ThemeFavoriteIcon.png?resize=1025%2C447\" alt=\"Theme Favorite Icon\" /></a>Theme Favorite Icon\n<p>Registered users who are logged into WordPress.org will see a heart icon above the download button on a theme&#8217;s detailed information page. When clicked, the heart icon turns red and the theme is added to your favorites list. To see your favorites list, visit the theme directory home page and click the Favorites tab.</p>\n<a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/ThemeFavorites.png\"><img class=\"size-full wp-image-48552\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/ThemeFavorites.png?resize=633%2C521\" alt=\"Themes Marked as Favorites\" /></a>Themes Marked as Favorites\n<p>To remove a theme from your favorites list, visit the theme&#8217;s detailed information page and click the heart icon.</p>\n<p>Unfortunately, you can&#8217;t install themes marked as favorite from the backend of WordPress since the Favorites tab doesn&#8217;t exist on the Add Themes page. However, I&#8217;ve <a href=\"https://core.trac.wordpress.org/ticket/34206\">created a ticket on Trac</a> to see if it can be added in time for WordPress 4.4. Keep in mind that like plugins, themes marked as favorites will show up on your WordPress.org user profile.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 08 Oct 2015 06:21:47 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:33;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"WPTavern: Measure Jetpack: An Independent Project Aimed at Measuring Jetpack’s Performance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48538\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"http://wptavern.com/measure-jetpack-an-independent-project-aimed-at-measuring-jetpacks-performance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3308:\"<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/ProjectJetpackBenchmark.png\"><img class=\"aligncenter size-full wp-image-48540\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/ProjectJetpackBenchmark.png?resize=658%2C292\" alt=\"Project Jetpack Benchmark\" /></a>Just about every time we publish an article about Jetpack, one or more readers <a href=\"http://wptavern.com/you-can-now-search-for-and-install-plugins-from-within-jetpack-manage#comment-88443\">leaves a comment</a> similar to the following, <em>I don&#8217;t use Jetpack because it slows down my site</em>. Many of the comments don&#8217;t link to or provide data that backs up their claim.</p>\n<p>Outside of the <a href=\"http://wptavern.com/benchmarks-indicate-jetpack-doesnt-negatively-impact-site-loading-times\">benchmarks</a> produced by the BruteProtect team late last year, there&#8217;s little evidence to support the claim that Jetpack negatively impacts a site&#8217;s performance. <a href=\"https://profiles.wordpress.org/ideag/#content-plugins\">Arūnas Liuiza</a>, a WordPress plugin developer, is working <a href=\"http://blog.arunas.co/project-measure-jetpack/\">on a new project</a> that hopes to solve the mystery of whether or not Jetpack causes sites to load more slowly.</p>\n<h2>Preparing the Testing Environment</h2>\n<p>In the next few weeks, Liuiza and his students will scour the WordPress plugin directory to find plugins with comparable features to Jetpack&#8217;s modules. The team is going to set up three identical WordPress sites with default Lorem Ipsum content.</p>\n<p>One site will act as the benchmark, another will run Jetpack, and the third will run plugins similar to Jetpack&#8217;s modules. Liuiza explains how his students will perform the benchmark process:</p>\n<blockquote><p>We’ll start the measuring, with different plugins/modules activated and deactivated. We’ll be doing 1-to-1 comparisons, as well as some combos. We are going to measure load times, as well as some stats reported by Query Monitor such as memory usage, database query count etc.</p></blockquote>\n<p>Liuiza says benchmark results will be published in a series of posts on his blog and on the <a href=\"https://www.facebook.com/groups/advancedwp/\">Advanced WordPress Facbook group</a>. Liuiza is asking for the community&#8217;s help to locate plugins that are feature-comparable to the modules in Jetpack.</p>\n<p>He&#8217;s also asking for advice on the testing methodology he and his students should use. There&#8217;s no timetable on when the results will be published as it&#8217;s considered a side project.</p>\n<h2>Benchmark Frontend Modules Only</h2>\n<p>Jetpack currently has 36 modules but some of them simply connect to services such as VaultPress or VideoPress. I think Liuiza and his team should concentrate on modules that potentially impact a site&#8217;s frontend performance as it doesn&#8217;t make sense to benchmark modules that are only for the backend.</p>\n<p>I&#8217;m doubtful that an independent study of Jetpack&#8217;s performance will solve the issue once and for all, especially if the results show that it doesn&#8217;t have much of an impact on sites as people think. However, it will be nice to have another set of data to point people to when it comes up in discussions.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 07 Oct 2015 18:41:11 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:34;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"Matt: Accelerated Mobile Pages &amp; WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45475\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"http://ma.tt/2015/10/accelerated-mobile-pages-wordpress/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:494:\"<p>As was just announced on <a href=\"https://vip.wordpress.com/2015/10/07/mobile-web/\">the VIP blog</a> and <a href=\"https://googleblog.blogspot.com/2015/10/introducing-accelerated-mobile-pages.html\">Google</a>, there&#8217;s a new open standard that competes with (or complements) Facebook&#8217;s Instant Articles. It&#8217;s easy for WordPress sites to support both, <a href=\"https://github.com/Automattic/amp-wp/\">you can check out this Github project to see the plugin code so far</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 07 Oct 2015 14:33:21 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:35;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"WPTavern: 10up Continues to Make Major Investments in WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48524\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"http://wptavern.com/10up-continues-to-make-major-investments-in-wordpress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4759:\"<p>In the last two years, <a href=\"http://10up.com/\">10up</a>, a web design and development agency has contributed to WordPress in significant ways. From <a href=\"http://wptavern.com/10up-sponsors-helen-hou-sandi-to-work-full-time-on-wordpress-core\">sponsoring Helen Hou-Sandi</a> to work full-time on WordPress core, to <a href=\"http://wptavern.com/drew-jaynes-to-lead-wordpress-4-2\">sponsoring Drew Jaynes</a> to lead the WordPress 4.2 development cycle. In a post published on the company&#8217;s blog, <a href=\"http://10up.com/blog/2015/commitments-open-web/\">10up announced</a> it will continue to invest in WordPress and other open source projects it works with on a daily basis.</p>\n<p>According to the announcement, 10up is sponsoring Jaynes to work on WordPress full-time. The company has also created a Platform Engineer position and although it&#8217;s not hiring to fill the role, the company has left the title open-ended as it continues to support and build web platforms such as <a href=\"http://10up.com/blog/2015/sponsoring-sanitize-css/\">santize.css</a> and <a href=\"http://10up.com/blog/2014/varying-vagrant-vagrants-future/\">Varying Vagrant Vagrants</a>.</p>\n<h2>Sponsoring Scott Kingsley Clark to Work on the Fields API Project</h2>\n<p>In a major show of support, 10up is sponsoring 100 hours of <a href=\"http://scottkclark.com/\">Scott Kingsley Clark’s</a> company time to work on the <a href=\"https://make.wordpress.org/core/tag/fields-api/\">Fields API Project</a>. Announced in May, the <a href=\"https://make.wordpress.org/core/2015/05/27/metadata-api-project-reborn-the-new-fields-api-project/\">Fields API Project</a> is an offshoot of the Metadata API project. The Fields API would allow developers to register fields and sections for WordPress objects. According to Clark, the goal is to initially cover the following WordPress objects:</p>\n<ul>\n<li>Customizer (retrofitting it beneath the existing Customizer API)</li>\n<li>User profile screen</li>\n<li>Post editor</li>\n<li>Settings screens (retrofitting it beneath the existing Settings API)</li>\n<li>And other areas in the future (Comment editor, Network Settings screens [see <a href=\"https://core.trac.wordpress.org/ticket/15691\">#15691</a>], Media modals, etc)</li>\n</ul>\n<p>10up believes that supporting the Fields API Project will help move it into a viable state to potentially be added to WordPress in the near-future, &#8220;As a company with a central mission of creating great publishing experiences, the user and developer experiences a fields API can improve are something we are particularly well-versed in,&#8221; Hou-Sandi said.</p>\n<p>Hou-Sandi goes on to explain that the web is built on open technologies that are usually maintained by small groups of people who rely on donations.</p>\n<blockquote><p>The balance between use and support of open source software leans heavily toward use, and that imbalance has become even more apparent. Even with increased awareness around the plight of projects integral to a safe web, initiatives like OpenSSL continue to operate on small donations and the volunteer efforts of a few. It takes time to convert pledges into action, and we’ve yet to see very many pledges at all, much less action.</p></blockquote>\n<p>The following quote written by Jake Goldman, <a href=\"http://10up.com/about/#employee-jake-goldman\">Founder and President of 10up</a>, explains why reinvesting in open source projects is so important not only for his company&#8217;s customers, but the WordPress userbase in general.</p>\n<blockquote><p>I’ve said repeatedly that nothing is more critical to the success of agencies that rely on community, open source software platforms than the continued success of those platforms. It is incumbent upon those who have leveraged free, open platforms with success to share that success back.</p>\n<p>By economically enabling world-class engineers to improve open platforms, we not only ensure that our customers continue to have a first class solution, we enable the next generation of builders, who can’t yet afford such resources, to further grow our ecosystem and the platform’s demand. I believe this is the social contract of open source, and as 10up grows, so to will our contributions to open source. It’s not just responsible citizenship, it’s good business.</p></blockquote>\n<p>It makes sense for companies whose businesses rely on open source software to find ways to reinvest time, energy, and money back into those projects less they disappear. That&#8217;s precisely what 10up is doing along with <a href=\"http://ma.tt/2014/09/five-for-the-future/\">a few other companies</a>. Let me know in the comments if and how your company is contributing back to open source software.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 06 Oct 2015 21:09:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:36;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"Matt: Scratch &amp; Sniff Whiskey\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45469\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"http://ma.tt/2015/10/scratch-sniff-whiskey/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:418:\"<p>Whether you&#8217;re curious for yourself or looking for a great gift for a scotch-loving friend, <a href=\"http://www.amazon.com/Essential-Scratch-Becoming-Whiskey-Know-It-All/dp/0544520602\">The Essential Scratch &#038; Sniff Guide to Becoming a Whiskey Know-It-All</a> from my friends Richard Betts, Crystal English Sacca, and Wendy MacNaughton is a must-buy. I have read this book myself and it smelled great.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 06 Oct 2015 20:04:13 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:37;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"WPTavern: You Can Now Search for and Install Plugins From Within Jetpack Manage\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48513\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"http://wptavern.com/you-can-now-search-for-and-install-plugins-from-within-jetpack-manage\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3229:\"<p>At the end of 2014, Jetpack 3.3 introduced a <a href=\"http://wptavern.com/jetpack-3-3-introduces-new-centralized-dashboard-for-managing-multiple-wordpress-sites\">centralized dashboard</a> that enables users to <a href=\"https://wordpress.com/plugins/jetpack\">manage Jetpack powered sites</a>. At the time, you could only do the following:</p>\n<ul>\n<li><strong>Plugin management:</strong> Turn plugins on or off with one click — per site or in bulk.</li>\n<li><strong>Initiate plugin updates:</strong> Update plugins for a single site or all sites in bulk.</li>\n<li><strong>Automatic updates:</strong> Turn on auto-updates for any plugin on a per-site basis or in bulk.</li>\n</ul>\n<p>Now you can <a href=\"http://jetpack.me/2015/10/01/new-plugin-browser/\">browse and install plugins</a> from the WordPress plugin directory on sites you own that use Jetpack with the <a href=\"https://jetpack.me/support/site-management/\">Manage module</a> activated. Visit <a href=\"https://wordpress.com/plugins/browse\">https://wordpress.com/plugins/browse</a> and choose the site you want to manage. Look for the Configure area on the sidebar and click the Add button to open the plugin browser.</p>\n\n<a href=\"http://wptavern.com/you-can-now-search-for-and-install-plugins-from-within-jetpack-manage/pluginbrowserinwp43\"><img src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/PluginBrowserInWP43.png?resize=1169%2C682\" class=\"attachment-full\" alt=\"Plugin Browser in WordPress 4.3\" /></a>\n<a href=\"http://wptavern.com/you-can-now-search-for-and-install-plugins-from-within-jetpack-manage/jetpackmanagepluginbrowser\"><img src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/JetpackManagePluginBrowser.png?resize=977%2C812\" class=\"attachment-full\" alt=\"Jetpack Plugin Browser\" /></a>\n\n<p>When the plugin directory <a href=\"http://wptavern.com/wordpress-plugin-directory-launches-new-design\">launched a redesign</a> earlier this year, <a href=\"http://wptavern.com/wordpress-plugin-directory-launches-new-design\">a common complaint</a> from readers is that the ability to see new plugins added to the directory was removed. Unlike the plugin browser in WordPress, the browser on WordPress.com displays new plugins.</p>\n<p>Both browsers display similar information in the detailed view with the exception that the WordPress.com browser doesn&#8217;t show a list of contributors. Enej Bajgorić, a member of the Jetpack development team, explains how to quickly install a plugin to a Jetpack site when browsing the WordPress plugin directory:</p>\n<blockquote><p>If you find yourself browsing the WordPress.org plugin repository and want to install the plugin on your Jetpack site, you can just replace the .org in the URL with .com and be taken to the new Plugin Browser where you can install the plugin with a single click. You will need to be logged into your WordPress.com account for this to work.</p></blockquote>\n<p>A plugin browser to search for and install plugins is another feature that makes Jetpack Manage a free, decent alternative to commercial services for managing multiple sites. If you manage multiple sites with Jetpack Manage, let us know what you think and what key features you&#8217;d like to see added.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 06 Oct 2015 18:29:41 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:38;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"Matt: Interview in French\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45463\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"http://ma.tt/2015/10/interview-in-french/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:196:\"<p>Si vous parlez français, <a href=\"http://www.journaldunet.com/solutions/dsi/1161757-interview-de-matt-mullenweg/\">vous pourriez profiter de cette interview avec moi sur Journal Du Net</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 05 Oct 2015 23:07:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:39;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"WPTavern: Tom Nowell on How Automattic Keeps Workers Healthy and Happy\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48490\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"http://wptavern.com/tom-nowell-on-how-automattic-keeps-workers-healthy-and-happy\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:12001:\"<hr />\n<p><a href=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/TomNowell.jpg\"><img class=\"alignright size-thumbnail wp-image-48491\" src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/10/TomNowell.jpg?resize=150%2C150\" alt=\"Tom Nowell\" /></a>This post was contributed by <a href=\"https://twitter.com/Tarendai\">Tom J Nowell</a>. Tom is a <a href=\"https://automattic.com/work-with-us/vip-wrangler/\">VIP Wrangler</a> at <a href=\"https://vip.wordpress.com\">WordPress.com VIP</a>, lead of the <a href=\"http://www.wptherightway.org/en/index.html\">WP The Right Way</a> project, <a href=\"http://tomjn.com\">blogger</a>, and community moderator at <a href=\"https://wordpress.stackexchange.com/\">WordPress Stack Exchange</a>. Tom will be speaking at <a href=\"https://nyc.wordcamp.org/2015/\">WordCamp New York</a> later this month on escaping and security.</p>\n<hr />\n<p>This is a story about my job as a <a href=\"http://vip.wordpress.com\" target=\"_blank\">VIP Wrangler</a>, what <a href=\"http://automattic.com\" target=\"_blank\">Automattic</a> does to keep Automatticians happy, and my battles with anxiety, <a href=\"http://hyperboleandahalf.blogspot.co.uk/2011/10/adventures-in-depression.html\" target=\"_blank\">depression</a>, and fear.</p>\n<h2>Joining the VIP Team</h2>\n<p>Almost a year ago, I worked for <a href=\"http://codeforthepeople.com/\">Code For The People</a>, a six person development agency that was in acquisition talks with Automattic. I remember at the beginning of the week, we thought an acquisition could happen before Xmas and by the following Friday, we were signing new employment contracts, and booking tickets to Lisbon for the VIP team meet up!</p>\n<p>I remember being the first to arrive, surrounded by people from the VIP team I&#8217;ve never met in person. We went out for dinner, learned how to do deploys, visited aquariums, gardens, and then went home.</p>\n<h2>The Happiness Rotation</h2>\n<p>After the meet up, I spent two months finishing contracts and started my Happiness Rotation. A happiness rotation is three weeks of working on the WordPress.com support team to get in touch with the problems end users are facing. Every Automattician has to go through a happiness rotation as part of their trial.</p>\n<p>Working the happiness rotation was hard. When I say this, I don&#8217;t mean it was an insurmountable task. I had a full-time Happiness Engineer available 24/7 to ask any question I wanted, a week of walkthroughs, supervised working, mountains of documentation, pre-written examples, and slack channels with friendly supportive people. I knew what to do, how to do it, and <a href=\"https://wordpress.stackexchange.com/users/736/tom-j-nowell\" target=\"_blank\">I&#8217;ve done it before</a>.</p>\n<h2>VIP Training</h2>\n<p>Despite this, I struggled, and VIP training began. Work at VIP fits into several sub roles that developers cycle through and training consists of a week in each role mentored by an experienced VIP Wrangler. Afterwards, we continue the cycle as full VIP Wranglers. Throughout the entire process, I had a general mentor for any and all things Automattic, be it mystery acronyms, or how to book a holiday.</p>\n<p>At this point, I realized my job had grown in scope and felt insurmountable. I didn&#8217;t know what was going on and there was still much to learn. Combined with a torrent of new notifications, p2s, and emails, I felt lost. GitHub scaled from two to three emails per day to hundreds, P2 posts filled my other inbox, people asked difficult questions, and the sheer amount of activity at Automattic was overwhelming.</p>\n<h2>Dealing With Adversity</h2>\n<p>In the last few years, I viewed Automattic as my career end goal and suddenly I was there, years ahead of schedule. Not just that, I was struggling. I couldn&#8217;t grasp what was going on and I felt paralyzed in the face of work. I grappled with the thought that I was bad at my job, didn&#8217;t belong there, and that I wouldn&#8217;t last the next six months. I had this feeling that at any time, they were going to pull me into a call and say it isn&#8217;t working out.</p>\n<p>A number of questions ran through my head. What would people think if they saw I left after the acquisition? Everyone&#8217;s treating it as a promotion and congratulating me. Maybe I&#8217;m not ready? I was handed a theme to review and struggling to read basic lines of code, mulling it over in my mind, why can&#8217;t I do this?</p>\n<p>Sometimes I had the wrong window open and was reviewing my code but was so preoccupied, I didn&#8217;t realize it. Today, it takes me four days to review 6,000 lines of code in a theme but at the time, it took me two weeks to move through 1,000 lines.</p>\n<h2>The Catch Up Calls</h2>\n<p>It&#8217;s at this point that I was introduced to the bi-weekly catch up call. The team leads would chat with each person individually every two weeks to find out how they were, what they were doing, and what they&#8217;d like to do the following week. It was a chance to flag any problems and plan ahead.</p>\n<p>I experienced nothing like this at CFTP or at any of my previous jobs and combined with the stalling work on the review, I panicked. My first catch up call was awkward and didn&#8217;t last long. My second catch up call didn&#8217;t go so well. I was at WordCamp Norway preparing to give a talk on <a href=\"http://www.wptherightway.org/en/index.html\" target=\"_blank\">WP The Right Way</a>. I sat in a quiet room and received a call on a Skype from my team lead.</p>\n<p>I felt as though I was put on the spot having to justify what I&#8217;d been doing the last two weeks, and trying to figure out how to spin weeks of panicking in front of a computer into a tale of bountiful code reviewing, pleasant Norwegian winters, and a smile.</p>\n<h2>Recovering From the Breakdown</h2>\n<p>Instead, I closed my machine and burst into tears. A few minutes later I opened my machine, apologized, and tried to explain what had happened. I was told they didn&#8217;t care how much work I was doing as long as I was learning and happy. A colleague picked up the review I was working on and noted that I was  thorough with the parts I reviewed.</p>\n<p>My team lead, Steph, checked up on me every two to three days for the next two weeks to make sure I was okay and tried to find what kind of work I took to best. I spent time on deploys, then moved on to a long rotation doing code review so that I could focus on particular tasks and build my confidence.</p>\n<p>While this was happening, another colleague asked if I was okay as he thought I was down. He introduced me to an internal slack channel called <a href=\"http://bluehackers.org/\" target=\"_blank\">Bluehackers</a> where other Automatticians who struggled could share their experiences. Seeing other people talk candidly about their problems made me recognize a lot of things I hadn&#8217;t considered, the most important being that I wasn&#8217;t alone.</p>\n<h2>I&#8217;m Not Alone</h2>\n<p>I wasn&#8217;t the only one who struggled some days and failed to get anything done. I wasn&#8217;t the only one who panicked when faced with new or even familiar tasks. Everyone at VIP was friendly and supportive, not because they knew of my situation, but because they are nice people. One time, my technical lead sent me three family sized pies because we had a slack discussion on pudding.</p>\n<p>Sometimes I don&#8217;t get anything done. Sometimes I struggle to do things I normally do effortlessly. Sometimes I turn off the video in calls because I&#8217;m still in bed. It&#8217;s 3PM and I can&#8217;t bring myself to get up, changed, and eat. There are so many projects I want to do. I have the knowledge, I have the resources, the support, the time, but they don&#8217;t get done, and it&#8217;s a struggle to explain why. Sometimes it&#8217;s things I know that need doing, like buying food or paying bills.</p>\n<h2>Confirmation Things are Working Out</h2>\n<p>A few months later I was in Seville at WordCamp Europe. Initially, I wasn&#8217;t going to go but decided I would regret it if I didn&#8217;t. I threw some clothes in a suitcase and purchased a flight. Large groups of people are scary, but I&#8217;ve found WordCamps tend to have familiar friendly faces mixed in. I can&#8217;t stress how big a boost it is to be able to see and make friends from event to event, yet still meet new people.</p>\n<p>Before I left, I found myself with my former boss and now colleague. He asked how I was getting along at Automattic. He asked me this before, and I said, &#8220;It was rough at the start but I think I&#8217;m there now.&#8221; He told me that everyone else at the company thought good of me and that I was fitting in well. It might have been simple statement but it meant a lot to me.</p>\n<h2>A Bout of Impostor Syndrome</h2>\n<p>I had real moments when I went to sleep thinking I was going to lose my job, that I might not be cut out to be a developer, and that I didn&#8217;t deserve the things I had. But throughout the entire process, my team leads and my colleagues tried to support me. They placed my well-being first and they proactively asked if I was ok when they suspected something was wrong, and sought to put real solutions in place where they could.</p>\n<p>They found other people with similar problems and tried to give me the ability to express what was happening, sharing their own problems coping, and what they were doing to keep on top of them. They gave praise and listened to good ideas, asked for help when they needed it, and they understood. Right now, I&#8217;m ok, but things have a habit of creeping up unnoticed, triggered by unexpected things.</p>\n<p>I get anxious about food at WordCamps if I don&#8217;t know what&#8217;s being served, I&#8217;m uncomfortable in social situations, and at times I have problems gathering the energy to do day-to-day things, but I&#8217;m lucky. I have a good job, a nice family, a comfortable apartment, and interesting work. My problems are mild and I know others have it worse. Most people are going to pretend everything&#8217;s ok but everyone needs a little help.</p>\n<h2>Suggestions for Employers and Struggling Employees</h2>\n<p>Automattic has things in place to make sure Automatticians lead healthy mental lives. We have an unlimited holiday allowance, a small expense budget to make traveling easier (e.g. a pot of tea at an airport or a massage), team meet ups, sabbaticals, and many others. Matt Mullenweg doesn&#8217;t want Automatticians to struggle, we work hard and it takes its toll. Often, we forget that we have to take care of our emotional and mental needs and give ourselves time.</p>\n<p>Consider creating your own internal Bluehackers group and give people avenues to express themselves when they need to. Make sure they&#8217;re happy, and that you care about their well-being more than their quality of work and output as reassurance goes a long way. Some companies have gone as far as setting minimum holiday allowances to force employees to spend time on themselves.</p>\n<p>If you&#8217;re dealing with problems like these, talk about it. Talk to a GP/Doctor, a friend, family, whatever works for you. Talking is hard, but it&#8217;s necessary. If someone opens up to you, listen. Don&#8217;t try to offer solutions, don&#8217;t compare and contrast, don&#8217;t try to offer sympathy, don&#8217;t expect it to be sorted out in a month&#8217;s time. Simply listen as that person chose to tell you, so give them space and respect.</p>\n<p>If you suspect someone is down, ask them if they&#8217;re ok and if you notice they bounce back, tell them, and tell them you&#8217;re glad! Highlight interesting things that happen, help them when they make a mistake, ask them when you make one yourself. But remember, sometimes all someone needs is a hug and a cup of tea to know that things are ok. Give them space, don&#8217;t ask for explanations, and let them know you&#8217;re there if you need them.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 05 Oct 2015 17:11:09 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:40;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"Post Status: How WordPress core development happens — Draft podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://poststatus.com/?p=14528\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://poststatus.com/how-wordpress-core-development-happens-draft-podcast/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2409:\"<p>Welcome to the Post Status Draft podcast, which you can find <a href=\"https://itunes.apple.com/us/podcast/post-status-draft-wordpress/id976403008\">on iTunes</a> and <a href=\"http://simplecast.fm/podcasts/1061/rss\">via RSS</a> for your favorite podcatcher. Brian and his guest co-host, <a href=\"https://twitter.com/williamsba\">Brad Williams</a> discuss some of today’s hottest, current WordPress news.</p>\n<p>This week Brian and Brad talk about how to get involved in WordPress core, what to expect when you do, how to navigate the waters of core development. They also discuss term meta, its use cases, how it works, and why it’s a great feature for WordPress 4.4.</p>\n<p>Brad is guest hosting this week, as Joe is out. He’s the co-founder of <a href=\"https://webdevstudios.com\">WebDevStudios</a>, a co-organizer for <a href=\"https://2015.us.wordcamp.org/about/organizers/\">WordCamp US</a>, and wrote <a href=\"http://bit.ly/prowp3\">Professional WordPress Design &amp; Development </a> (my go-to book on WordPress development). You can follow Brad on Twitter <a href=\"https://twitter.com/williamsba\">@williamsba</a>.</p>\n<a href=\"https://audio.simplecast.fm/18028.mp3\">https://audio.simplecast.fm/18028.mp3</a>\n<p><a href=\"http://audio.simplecast.fm/18028.mp3\">Direct Download</a></p>\n<h3>Topics</h3>\n<p>WordPress core development process:</p>\n<ul>\n<li><a href=\"https://make.wordpress.org/core/components/\">WordPress core components</a></li>\n<li><a href=\"https://make.wordpress.org/core/features-as-plugins/\">Features as plugins</a></li>\n<li><a href=\"https://core.trac.wordpress.org/\">WordPress Trac </a></li>\n<li><a href=\"https://codex.wordpress.org/Core_Team\">The WordPress core team</a></li>\n<li><a href=\"https://make.wordpress.org/chat/\">How to get on WordPress Slack discussions</a></li>\n</ul>\n<p>Term meta:</p>\n<ul>\n<li><a href=\"https://poststatus.com/?s=term+meta\">Term Meta posts/notes on Post Status</a> (some members only content)</li>\n<li><a href=\"https://poststatus.com/notes/the-case-for-term-meta-and-a-roadmap-for-making-it-happen/\">The case for term meta</a> (members only)</li>\n<li><a href=\"https://core.trac.wordpress.org/changeset/34529\">Term meta lands in core</a></li>\n<li><a href=\"https://make.wordpress.org/core/tag/taxonomy/\">Term Meta posts on Make Core</a></li>\n<li><a href=\"http://github.com/sc0ttkclark/wordpress-fields-api\">WordPress Fields API project</a></li>\n</ul>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 04 Oct 2015 00:55:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Katie Richards\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:41;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"WPTavern: WP101 Founded by Shawn Hesketh Turns 7 Years Old\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48481\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"http://wptavern.com/wp101-founded-by-shawn-hesketh-turns-7-years-old\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1903:\"<p>Earlier this week, WordPress video training site <a href=\"https://www.wp101.com/\">WP101</a>, founded by Shawn Hesketh, <a href=\"https://www.wp101.com/birthday/\">turned seven years old</a>. Since launching in 2008, Hesketh&#8217;s videos have been viewed more than a million times by over 500k people. He&#8217;s also re-recorded the videos that make up the WP101 series 17 times. With seven years of experience under his belt, I asked Hesketh what he would have done differently in the beginning.</p>\n<p>&#8220;From a technical standpoint, I wish I’d picked a solid membership plugin that would have enabled us to grow. We’re planning a costly migration in the coming months, and a better membership plugin might have saved us the considerable hassle and cost,&#8221; Hesketh told the Tavern.</p>\n<p>Technical issues aside, Hesketh believes his business&#8217; success is largely due to his focus on serving people, &#8220;It’s one thing to create an online course and hope people discover it. But it takes much more dedication to actually engage people on a daily basis, take the time to understand their goals, and then help them get clear on how to accomplish those goals,&#8221; he said.</p>\n<p>Hesketh doesn&#8217;t have any regrets but wishes he launched the question and answer forum on the first day, &#8220;Its given me the opportunity to answer questions that may not be covered in our videos. That’s the real value that WP101 brings to the table, real people helping others,&#8221; he said.</p>\n<p>WP101 launched around the same time as a lot of commercial theme shops such as iThemes, StudioPress, and WooThemes. Although WP101 doesn&#8217;t sell commercial themes or plugins, Hesketh has carved out a space in the WordPress ecosystem that enables him to make a living. If you use WP101 or have in the past, I&#8217;d love to hear what you think of his videos in the comments.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 03 Oct 2015 01:33:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:42;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"WPTavern: The Top 100 Active WordPress Themes and Plugins on GoDaddy’s Hosting Network\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48462\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"http://wptavern.com/the-top-100-active-wordpress-themes-and-plugins-on-godaddys-hosting-network\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5167:\"<p>It was a warm, sunny afternoon in Tempe, AZ as I walked with a group of GoDaddy employees on our way to lunch during Pressnomics 3 earlier this year. It&#8217;s the first time I met Mendel Kurland, Xopher Carfi, and Kurt Payne in person. During lunch, we discussed a number of topics from the efforts made to change the company&#8217;s image, to ideas that help the WordPress community.</p>\n<p>I suggested to the team that GoDaddy create a billboard chart that shows the most popular themes and plugins used across its network. Not only would the information be beneficial to the company, it would also give the WordPress community valuable insight into what plugins and themes are used on a webhosting network with millions of customers.</p>\n<p>Nine months after our discussion, GoDaddy turned the idea into reality with the <a href=\"https://garage.godaddy.com/wordpress-hot-100/\">Hot 100</a>.</p>\n<a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/GoDaddyHot100.png\"><img class=\"size-full wp-image-48463\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/GoDaddyHot100.png?resize=1025%2C682\" alt=\"Top 100 Plugins and Themes of The Week\" /></a>Top 100 Plugins and Themes of The Week\n<p>GoDaddy tracks which themes and plugins are activated across the millions of sites it hosts and puts the 100 most popular of each into a list. The list is generated each week and places the previous week of results into an archive allowing you to monitor trends.</p>\n<p>Similar to the <a href=\"http://www.billboard.com/charts/hot-100\">Billboard Hot 100</a>, you can see the current rank of a plugin or theme, whether it&#8217;s moved up or down, and what its rank was the previous week. With an influential list like the Hot 100, it would be easy to accept paid listings. Carfi, confirms <a href=\"https://garage.godaddy.com/webpro/wordpress/hot-100-wordpress-plugins-and-themes/\">it&#8217;s not possible</a> to purchase placement.</p>\n<h2>How the Lists Are Generated</h2>\n<p>The Hot 100 is determined by ranking the net change in the number of active installs of WordPress plugins and themes in aggregate across GoDaddy&#8217;s hosting network. It looks at plugins and themes that are active at the time of the analysis and does not include plugins or themes that are deactivated.</p>\n<p>Instead of using the total number of active installs, the Hot 100 looks at the week-over-week change in active installs. This enables the list to determine which plugins and themes are hot or part of a rising trend. It also prevents bias towards plugins that already have a large install base such as Jetpack.</p>\n<p>Interestingly, themes on the list that are non-GPL are specifically noted and link to the Hot 100 instead of their corresponding theme page. In a <a href=\"https://www.facebook.com/groups/advancedwp/permalink/1025849944143886/\">post published</a> to the Advanced WordPress Facebook group, Jeff King, Senior Vice President of Hosting at GoDaddy explains why.</p>\n<blockquote><p>One great recommendation and valuable bit of feedback we received is that, since the community embraces GPL, we should reflect that ethos in the Hot 100 list. While some non-GPL themes or plugins may occasionally show up in the list due to the fact that some non-GPL items still exist in the ecosystem, we don&#8217;t necessarily need to link to them. As of next week, we&#8217;ll be removing links to non-GPL themes and plugins.</p></blockquote>\n<h2>The Hot 100 Is a Valuable Resource</h2>\n<p>Although WordPress.org provides stats for plugin and theme authors, you can&#8217;t determine where they&#8217;re being used. The GoDaddy Hot 100 gives the public and developers of popular plugins and themes an opportunity to see how well they&#8217;re doing on one of the largest webhosts in the industry. While Jetpack and Akismet are the two most active plugins and seven default themes make up the top 10 themes, it&#8217;s the 25th-100th rankings that I find interesting.</p>\n<p>For example, <a href=\"https://wordpress.org/plugins/hello-dolly/\">Hello Dolly</a> which ships with WordPress and is activated by default after installation is ranked 27th this week. Last week, it ranked 38th meaning a lot of new installs of WordPress have taken place. This indicates that even though a lot of customers disable the plugin at some point after installation, it remains active on many sites hosted by GoDaddy.</p>\n<p>One of the largest jumps I&#8217;ve seen so far is the <a href=\"https://wordpress.org/plugins/image-widget/\">Image Widget</a> plugin by Modern Tribe. It was ranked 95th last week and 31st this week. It would be interesting to know why a lot of new WordPress installs are activating this plugin on GoDaddy hosted sites this week versus last week.</p>\n<p>The <a href=\"https://garage.godaddy.com/wordpress-hot-100/\">Hot 100</a> is a valuable resource and I encourage you to see if your favorite plugins and themes made the list. Although it&#8217;s specific to GoDaddy, do you think the data is valuable? Would you like to see other large webhosting companies provide a glimpse into the most active WordPress themes and plugins used across their network?</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 02 Oct 2015 18:51:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:43;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"WPTavern: Jetpack 3.7.2 Patches Two Security Vulnerabilities\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48458\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"http://wptavern.com/jetpack-3-7-2-patches-two-security-vulnerabilities\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1336:\"<p>Jetpack 3.7.2 is <a href=\"https://wordpress.org/plugins/jetpack/\">available for download</a> and patches two security vulnerabilities. The first is a cross-site scripting vulnerability in the contact form due to improper input sanitation that affects Jetpack 3.7.0 and below. Marc-Alexandre Montpas of <a href=\"https://sucuri.net/\">Sucuri</a> is credited with responsibly disclosing the vulnerability.</p>\n<p>The second is an information disclosure vulnerability present in certain hosting configurations responsibly disclosed by Jaime Delgado Horna of <a href=\"http://listae.com/\">Listae</a>. In addition to patching the vulnerabilities, 3.7.2 also fixes an error with the REST API that creates multiple drafts and published posts. Other notable fixes includes:</p>\n<ul>\n<li>Updating the Google+ logo in our sharing buttons.</li>\n<li>Adding custom capabilities for module management for multisite installs.</li>\n<li>Fixing a bug that was sending the contact form response fields in the wrong order.</li>\n</ul>\n<p>Montpas has <a href=\"https://blog.sucuri.net/2015/10/security-advisory-stored-xss-in-jetpack.html\">additional information</a> on the cross-site scripting vulnerability discovered in Jetpack on the Sucuri blog, including a timeline of events. Please update to Jetpack 3.7.2 as soon as possible to protect your sites.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 02 Oct 2015 16:12:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:52:\"WPTavern: WPWeekly Episode 208 – A Nod to the King\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48447\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"http://wptavern.com/wpweekly-episode-208-a-nod-to-the-king\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2841:\"<p>In this episode of WordPress Weekly, <a href=\"http://marcuscouch.com/\">Marcus Couch</a> and I discuss the death of Alex King who was a pillar of the WordPress project. King passed away a few days ago from colon cancer. We share stories of meeting and discussing WordPress topics with King and describe his many contributions to WordPress. King will be dearly missed by the WordPress community.</p>\n<p>During the second half of the show, we discuss upcoming changes in WordPress 4.4, the lessons I learned moderating comments on WP Tavern, and WordCampus renaming to WPCampus.</p>\n<h2>Stories Discussed:</h2>\n<p><a href=\"http://wptavern.com/alex-king-founder-of-crowd-favorite-passes-away\">Alex King, Founder of Crowd Favorite Passes Away</a><br />\n<a href=\"http://alexking.org/blog/2015/08/24/rememberances\">Alex King&#8217;s Final Request</a><br />\n<a href=\"http://wptavern.com/wp-super-cache-1-4-5-patches-xss-vulnerability\"> WP Super Cache 1.4.5 Patches XSS Vulnerability</a><br />\n<a href=\"http://wptavern.com/lessons-i-learned-moderating-comments-in-wordpress\"> Lessons I Learned Moderating Comments in WordPress</a><br />\n<a href=\"http://wptavern.com/wordcampus-renames-event-to-wpcampus\"> WordCampus Renames Event to WPCampus</a><br />\n<a href=\"http://wptavern.com/wordpress-4-4-to-possibly-rearrange-fields-to-the-comment-form\"> WordPress 4.4 to Possibly Rearrange Fields to the Comment Form</a><br />\n<a href=\"http://wptavern.com/wordpress-4-4-removes-the-view-post-and-get-shortlink-buttons-from-the-post-editor\"> WordPress 4.4 Removes the View Post and Get Shortlink Buttons From the Post Editor</a></p>\n<h2>Plugins Picked By Marcus:</h2>\n<p><a href=\"https://wordpress.org/plugins/cf7-customizer/\">Contact Form 7 Customizer</a> allows you to alter items like spacing and button size of the contact form using the customizer.</p>\n<p><a href=\"https://wordpress.org/plugins/view-admin-as/\">View Admin As</a> lets you simulate what a site looks like from a user with a specific role or capability.</p>\n<p><a href=\"https://wordpress.org/plugins/grayscale-images/\">Grayscale Images</a> converts images to gray-scale and displays the colored image hovered over.</p>\n<h2>WPWeekly Meta:</h2>\n<p><strong>Next Episode:</strong> Wednesday, October 7th 9:30 P.M. Eastern</p>\n<p><strong>Subscribe To WPWeekly Via Itunes: </strong><a href=\"https://itunes.apple.com/us/podcast/wordpress-weekly/id694849738\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via RSS: </strong><a href=\"http://www.wptavern.com/feed/podcast\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Subscribe To WPWeekly Via Stitcher Radio: </strong><a href=\"http://www.stitcher.com/podcast/wordpress-weekly-podcast?refid=stpr\" target=\"_blank\">Click here to subscribe</a></p>\n<p><strong>Listen To Episode #208:</strong><br />\n</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 01 Oct 2015 09:25:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"WPTavern: 6 WordPress Plugins That Take Native Comments to the Next Level\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48414\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"http://wptavern.com/6-wordpress-plugins-that-take-native-comments-to-the-next-level\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:12366:\"<p>Last week, I <a href=\"http://wptavern.com/lessons-i-learned-moderating-comments-in-wordpress\">shared the lessons I learned</a> and the drawbacks to moderating comments in WordPress. In this post, I highlight six plugins that solve a problem I encountered or enhance comments for both readers and site administrators. All of the plugins are free of charge and available from the <a href=\"https://wordpress.org/plugins/\">WordPress plugin directory</a>.</p>\n<h2>Problem Solvers</h2>\n<h3>Crowd Control</h3>\n<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlPluginBanner.png\"><img class=\"aligncenter size-full wp-image-48420\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlPluginBanner.png?resize=799%2C253\" alt=\"Crowd Control Plugin Banner\" /></a>I discovered that not all comments need to be moderated. <a href=\"https://wordpress.org/plugins/crowd-control/\">Crowd Control</a>, by Postmatic, gives readers the ability to report comments they feel don&#8217;t adhere to a site&#8217;s commenting policy.</p>\n<p>When enabled, a new option is displayed on the <strong>General &#8211; Discussion</strong> settings page. You can configure how many reports a comment needs before it&#8217;s sent to the moderation queue and whether administrators should be notified when it happens.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlSettings.png\"><img class=\"size-full wp-image-48421\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlSettings.png?resize=798%2C174\" alt=\"Crowd Control Settings\" /></a>Crowd Control Settings\n<p>If an administrator approves a comment that&#8217;s in moderation due to hitting the threshold, it won&#8217;t end up back in the moderation queue. This gives administrators the last word on whether a comment is acceptable or not.</p>\n<a href=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlInAction.png\"><img class=\"size-full wp-image-48422\" src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlInAction.png?resize=686%2C202\" alt=\"Crowd Control in Action\" /></a>Crowd Control in Action\n<p>If you think a comment needs an administrator&#8217;s attention or does not adhere to the WP Tavern <a href=\"http://wptavern.com/comment-policy\">commenting policy</a>, hover over the comment and click the report button. A new column is added to <strong>edit-comments.php</strong> that displays how many reports a comment has. It&#8217;s important to note that detailed information of who reported the comment is not saved to the database.</p>\n<a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlReportedColumn.png\"><img class=\"size-full wp-image-48423\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/CrowdControlReportedColumn.png?resize=807%2C193\" alt=\"Reported Comments Column\" /></a>Reported Comments Column\n<p>The system is open for abuse but I trust that the Tavern readership will use it responsibly.</p>\n<h3>Show Parent Comment</h3>\n<p>Comments that are pending moderation in the WordPress backend that are in response to another comment are hard to moderate. <a href=\"https://wordpress.org/plugins/show-parent-comment/\">Show Parent Comment</a>, developed by <a href=\"https://profiles.wordpress.org/stephencronin/\">Stephen Cronin</a>, adds a <strong>Show More</strong> dropdown to the <strong>edit-comments.php</strong> screen that allows administrators to see the text of the comment that a person is responding too.</p>\n<p><a href=\"http://wptavern.com/6-wordpress-plugins-that-take-native-comments-to-the-next-level#gallery-48414-1-slideshow\">Click to view slideshow.</a><br />\nI&#8217;ve used this plugin for more than two weeks and I enjoy the user interface. It looks and acts as if it&#8217;s a natural part of WordPress. Chris Xoff <a href=\"https://core.trac.wordpress.org/ticket/33627\">created a ticket</a> in Trac with the suggestion that a user interface element like the one in Cronin&#8217;s plugin be added to core. If you have feedback on the best way to accomplish this, please add it to the ticket.</p>\n<h2>Enhancements to Native Comments</h2>\n<h3>Epoch</h3>\n<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/EpochPluginBanner.png\"><img class=\"aligncenter size-full wp-image-48415\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/EpochPluginBanner.png?resize=806%2C255\" alt=\"Epoch Plugin Banner\" /></a><a href=\"https://wordpress.org/plugins/epoch/\">Epoch</a> is a plugin developed by Postmatic and a few other contributors that enhances WordPress&#8217; comment system. Unlike services such as Disqus or Livefyre that replace the comment system, Epoch adds features to WordPress&#8217; native comments. This allows you to keep comments within your database at all times without relying on a third-party.</p>\n<p>Epoch applies a series of visual enhancements to the comment form. Replies from the post author are a different color from regular responses and the date and time the comment is written is displayed at the top. Epoch also uses Ajax to send and receive comments which eliminates the need to refresh the page.</p>\n<a href=\"http://wptavern.com/6-wordpress-plugins-that-take-native-comments-to-the-next-level#gallery-48414-2-slideshow\">Click to view slideshow.</a>\n<p>Epoch has a front end moderation capability that allows site administrators to approve, trash, or spam comments. Unlike the native comment form, Epoch doesn&#8217;t load the comments unless the browser reaches a certain point on a post or is accessed via a direct link.</p>\n<p>In most instances, the comment form loads quickly but on certain mobile devices, the lack of speed is noticeable. The team is aware of the performance issues and is attacking the problem with a three stage approach.</p>\n<p>Epoch relies on JavaScript to function so if a visitor browsing your site has JavaScript disabled, the comments don&#8217;t load. Again, the team is aware of this issue and is creating a fallback to WordPress&#8217; native comment system if the files can&#8217;t be retrieved from its CDN or JavaScript is disabled.</p>\n<h3>Basic Comment Quicktags</h3>\n<p><a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/BasicCommentQuicktagPluginBanner.png\"><img class=\"aligncenter size-full wp-image-48426\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/BasicCommentQuicktagPluginBanner.png?resize=769%2C251\" alt=\"Basic Comment Quicktag Plugin Banner\" /></a>In WordPress 4.3, the allowed HTML tags text displayed near the comment form <a href=\"https://core.trac.wordpress.org/ticket/30157\">was removed</a>. The tags were removed because they&#8217;re note relevant and confusing to most users. While I agree that the text is not relevant, I think the comment form should have basic text formatting buttons so readers don&#8217;t have to remember and manually type HTML tags.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/BasicCommentQuicktagsOnTheTavern.png\"><img class=\"size-full wp-image-48428\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/BasicCommentQuicktagsOnTheTavern.png?resize=665%2C368\" alt=\"Basic Comment Quicktags in Action\" /></a>Basic Comment Quicktags in Action\n<p>Once Basic Comment Quicktags is installed, navigate to <strong>Settings &#8211; Discussion</strong> and check the box to enable them for comments. When enabled, the comment text area will have Bold, Italic, Link and Quote buttons. The best part of this plugin is that it exposes a built-in core feature using the <a href=\"http://codex.wordpress.org/Quicktags_API\">Quicktags API</a> added to WordPress 3.3. Text formatting buttons in the comment area is a courtesy I&#8217;d like more site owners to give to readers.</p>\n<h3>Simple Comment Editing</h3>\n<p><a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/SimpleCommentEditingPluginBanner.png\"><img class=\"aligncenter size-full wp-image-48429\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/10/SimpleCommentEditingPluginBanner.png?resize=764%2C262\" alt=\"Simple Comment Editing Plugin Banner\" /></a><a href=\"https://wordpress.org/plugins/simple-comment-editing/\">Simple Comment Editing</a>, developed by <a href=\"https://profiles.wordpress.org/ronalfy/\">Ronald Huereca</a>, adds the ability for readers to edit their comments in a limited time frame. By default, readers have five minutes to edit their comment once it&#8217;s submitted. Although no configuration is necessary, you can alter the time and behavior of the plugin by using <a href=\"https://github.com/ronalfy/simple-comment-editing#wordpress-filters\">actions and filters</a>. I&#8217;ve changed the time limit to 15 minutes on the Tavern to make sure readers have plenty of time to make edits.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/SimpleCommentEditingInAction.png\"><img class=\"size-full wp-image-48430\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/SimpleCommentEditingInAction.png?resize=676%2C173\" alt=\"Simple Comment Editing Countdown Timer\" /></a>Simple Comment Editing Countdown Timer\n<p>With Simple Comment Editing installed, the amount of contact form submissions and requests to edit a comment have gone down considerably.</p>\n<h3>Postmatic</h3>\n<p><a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/PostmaticPluginBanner.png\"><img class=\"aligncenter size-full wp-image-48432\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/PostmaticPluginBanner.png?resize=801%2C235\" alt=\"Postmatic Plugin Banner\" /></a><a href=\"https://wordpress.org/plugins/postmatic/\">Postmatic</a> is a plugin that <a href=\"https://gopostmatic.com/\">ties into a service</a> and has a number of features. Readers can subscribe to posts or to comments and receive updates via email. Postmatic has a beautiful email template that shows the most recent reply, the commenter&#8217;s Gravatar, and a recap of the post and conversation.</p>\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/PostmaticCommentEmailTemplate.png\"><img class=\"size-full wp-image-48433\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/10/PostmaticCommentEmailTemplate.png?resize=727%2C833\" alt=\"Postmatic Comment Email Template\" /></a>Postmatic Comment Email Template\n<p>Readers can respond to comments via email without having to visit the comment form. Site administrators can reply, trash, or submit comments to Akismet via email. It&#8217;s important to note that Postmatic is not a third-party commenting service. Instead, it uses the native comment system in WordPress allowing you to keep and own your data at all times.</p>\n<p>While I moderate comments from the WordPress mobile app or the WordPress backend, Postmatic is a great fallback. I also think the email template looks great and offers a better user experience than the comment notification emails provided by WordPress. Postmatic <a href=\"https://gopostmatic.com/technology/\">does a lot more</a> than what I describe above but for the purpose of this article, I focused on the comment portion of the service.</p>\n<p>Postmatic is a new addition to the Tavern that I encourage you to try. After trying it out, please tell me about your experience. I especially wany to know if it&#8217;s easier to keep track of and take part in conversations.</p>\n<h2 class=\"font-headlines\">Notifications That a Comment in Moderation is Approved</h2>\n<p>One of the problems I&#8217;ve yet to solve is being addressed by a number of WordPress contributors in <a href=\"https://core.trac.wordpress.org/ticket/33717#comment:6\">ticket 33717</a>. If all goes well, it&#8217;s possible this feature will be added to WordPress 4.4. Once added, readers whose comments end up in the moderation queue will automatically be notified by WordPress when it&#8217;s approved.</p>\n<h2>It’s Not Perfect but It&#8217;s an Improvement</h2>\n<p>Even with all the features these plugins provide, I don&#8217;t think the comment system in WordPress or the form on WP Tavern is perfect. I&#8217;m not sure if perfection of either can be achieved. However, I think both are improvements over the previous iterations. If there&#8217;s a plugin you use to improve WordPress&#8217; native comments or its moderation system, let me know about it in the comments.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 01 Oct 2015 08:28:33 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Donncha: The Web Won’t Forget Alex King\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"http://z9.io/?p=89499737\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:54:\"http://z9.io/2015/09/29/the-web-wont-forget-alex-king/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2811:\"<p>If you use a WordPress site, either as a visitor or owner, you&#8217;re using code that <a href=\"http://alexking.org/\">Alex King</a>, one of the original developers of WordPress, worked on. </p>\n<p>He passed away after fighting <a href=\"http://alexking.org/blog/thread/cancer\">cancer for 2 years</a> but his online presence lives on in the form of his blog with it&#8217;s deep archive of posts going back years, and in so much code that it&#8217;s humbling to look at his <a href=\"http://alexking.org/projects\">projects page</a>. Looking through the svn log of WordPress trunk shows he still had a hand in helping the WordPress project until relatively recently:</p>\n<blockquote><p>trunk$ svn log|grep alexkingorg<br />\nprops alexkingorg for the initial, long-suffering patch.<br />\nprops alexkingorg. fixes <a href=\"https://core.trac.wordpress.org/ticket/24162\">#24162</a>.<br />\nProps alexkingorg<br />\n`wp.media` instead of just `media`. props alexkingorg, see #22676.<br />\nAdd $post_ID context to the pre_ping filter. props alexkingorg, devesine. fixes #18506.<br />\nAdd filter so the users can select custom image sizes added by themes and plugins, props alexkingorg, fixes #18520<br />\nesc_textarea() and application for obvious textarea escaping. props alexkingorg. fixes #15454<br />\nEscape links by default.  Props alexkingorg. see #13051<br />\nSafely include class-json.php, class-simplepie.php and class-snoopy.php, props alexkingorg, fixes #11827<br />\nFix user creation from admin after changes for #10751. Fixes #10811 props alexkingorg.<br />\nHooks needed to allow alternate category admin inteface. Props alexkingorg. fixes #3408<br />\nWrap cat name in CDATA. props alexkingorg.  fixes #3252</p></blockquote>\n<p>I&#8217;m sorry I never met Alex, however I remember working virtually with him and Adam Tow on AllThingsD which seems like a lifetime away now. Adam has <a href=\"http://tow.com/2015/09/28/remembering-alex-king/\">a great article</a> on Alex on his blog, as does Matt <a href=\"http://ma.tt/2015/09/remembering-alex-king/\">who went into detail</a> about Alex&#8217;s involvement with WordPress going back to the days of b2. I had completely forgotten <a href=\"http://alexking.org/blog/2004/01/25/wordpress-css-style-competition\">the CSS competition</a> he mentioned!</p>\n<p>Alex, your legacy lives on. </p>\n\n<p><strong>Related Posts</strong><ul><li> <a href=\"http://z9.io/2003/03/10/b2-hacks/\" rel=\"bookmark\" title=\"Permanent Link: b2 Hacks\">b2 Hacks</a></li><li> <a href=\"http://z9.io/2007/12/12/how-to-find-cocaine-in-ireland/\" rel=\"bookmark\" title=\"Permanent Link: How to find cocaine in Ireland\">How to find cocaine in Ireland</a></li><li> <a href=\"http://z9.io/2003/05/31/king-of-hearts/\" rel=\"bookmark\" title=\"Permanent Link: King Of Hearts\">King Of Hearts</a></li></ul></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 29 Sep 2015 20:44:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Donncha\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"WPTavern: WordPress 4.4 Removes the View Post and Get Shortlink Buttons From the Post Editor\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48395\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:102:\"http://wptavern.com/wordpress-4-4-removes-the-view-post-and-get-shortlink-buttons-from-the-post-editor\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2435:\"<p>In WordPress 4.4, the View Post button in the post editor is disappearing in favor of a clickable permalink. Four years ago, <a href=\"http://scribu.net/\">Scribu</a>, who is a <a href=\"http://scribu.net/blog/left-wordpress.html\">former WordPress contributor</a>, created ticket <a href=\"https://core.trac.wordpress.org/ticket/18306\">#18306</a>. In the ticket, Scribu explains that the View Post button is redundant functionality and suggests that it be removed in favor of a clickable permalink.</p>\n<p>Here are two screenshots of the post editor. The first is WordPress 4.3 and the second is WordPress 4.4. Clicking the permalink allows you to preview the post in its current state. Notice the slug part of the URL is in bold. You need to click the Edit button to edit the permalink.</p>\n<a href=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/09/WP43PermalinkEditor.png\"><img class=\"wp-image-48397 size-full\" src=\"http://i2.wp.com/wptavern.com/wp-content/uploads/2015/09/WP43PermalinkEditor.png?resize=568%2C213\" alt=\"WordPress 4.3 Post Editor\" /></a>WordPress 4.3 Post Editor\n<a href=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/09/WP44PermalinkEditor.png\"><img class=\"wp-image-48398 size-full\" src=\"http://i0.wp.com/wptavern.com/wp-content/uploads/2015/09/WP44PermalinkEditor.png?resize=570%2C188\" alt=\"WordPress 4.4 Post Editor\" /></a>WordPress 4.4 Post Editor\n<p>Not only does this change remove redundant functionality, it removes a UI element from the page. Enhancements like these are a huge win for WordPress because it makes the interface simpler without permanently removing the button&#8217;s purpose.</p>\n<p>In addition to the View Post button, the Get Shortlink button is also removed. The button shows up if you’re using a custom shortlink and can be re-enabled using code or a plugin. For most users, the Edit button is the only one they&#8217;ll see between the post title and content box.</p>\n<p>I expect some users will be frustrated as they go through the process of changing their workflow but overall, I think it&#8217;s a great improvement. What do you think?</p>\n<hr />\n<p>If you&#8217;re using the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress beta testing plugin</a> by Peter Westwood, I encourage you to set it to bleeding edge nightlies and update your site. You&#8217;ll be able to test this change and others during the WordPress 4.4 development cycle.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 29 Sep 2015 19:22:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"Matt: Remembering Alex King\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"http://ma.tt/?p=45372\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"http://ma.tt/2015/09/remembering-alex-king/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:6442:\"<p><a href=\"http://ma.tt/2009/05/wordcamp-sf-2009-2/mcm_0235-2/\"><img class=\"alignright\" src=\"http://i1.wp.com/ma.tt/files/2009/05/MCM_0235.JPG?resize=276%2C415\" alt=\"\" /></a>Alex speaking at WordCamp SF 2009One of the original WordPress developers, Alex King, has passed <a href=\"http://alexking.org/blog/thread/cancer\">from cancer</a> at far too young an age. Alex actually <a href=\"http://alexking.org/blog/2002/10/24/b2-coding\">got involved with b2 in 2002</a> and was active in the forums and the &#8220;hacks&#8221; community there.</p>\n<p>Alex had a background as a designer before he learned development, and I think that really came through as he was one of those rare people who thought about the design and usability of his code, the opposite of most development that drifts toward entropy and complexity. One of my favorite things about Alex was how <em>darn tasteful</em> he was. He would think about every aspect of something he built, every place someone could click, every path they could go down, and gave a thoughtfulness to these paths that I still admire and envy today.</p>\n<p>As an example look&nbsp;at his <a href=\"http://alexking.org/project/post-formats-admin-ui\">project page (essentially a category archive) for the Post Formats Admin UI</a>, isn&#8217;t that clever and intuitive how the posts connect together, and when more time passes in the thread it&#8217;s <a href=\"https://cloudup.com/ceWJeb9zcK6\">shown as a break</a>. It&#8217;s classic Alex: something simple and thoughtful that in hindsight is so gobsmackingly obvious you wonder why everything doesn&#8217;t work that way, but you never would have imagined it beforehand. And Alex wouldn&#8217;t just imagine it and do it for himself, he released his best work as open source, as a gift to the community and the world, over and over and over again.</p>\n<p>Back when WordPress was getting started Alex was a celebrity of the b2 world, his hacks (plugins before plugins) were&nbsp;some of the coolest ones around. We had a ton of overlapping interests in web standards, photography, development, and gadgets so&nbsp;we frequently read and commented on each other&#8217;s blogs. I would never miss a post on his site, and that&#8217;s back when we were both doing one or more posts a day. To get a sense of Alex it&#8217;s worth <a href=\"http://alexking.org/blog\">exploring his blog</a> &#8212; he was a clear thinker and therefore a clear writer.&nbsp;The straightforward nature Alex wrote with was something I always admired about him.</p>\n<p>We <a href=\"http://alexking.org/blog/2003/07/08/wordpress-development\">discussed WordPress early on</a>, Alex <a href=\"http://alexking.org/blog/2003/07/23/wordpress-hacks\">signed up to help with what later became the plugin directory</a>, and <a href=\"http://alexking.org/blog/2004/01/25/wordpress-css-style-competition\">his CSS competition</a> (look at those prizes! and notice it&#8217;s all GPL) was hugely influential on the path to themes, and <a href=\"http://alexking.org/blog/2003/08/15/wordpress-dev\">he officially became a contributing developer in August of 2003</a>.</p>\n<p>The list of what Alex was one of the first to do in the WordPress community is long, and <em>in hindsight</em> seems gobsmackingly obvious, which is the sign of innovation. I smile when I think of how he <a href=\"http://alexking.org/blog/2003/10/02/moving-to-denver\">moved from the Bay area to Denver</a> before it was cool, or his <a href=\"https://cloudup.com/cL9v2RKEI0T\">love of scare quotes</a>. Once there was something going on in WordPress and he called me to talk about it, I was so surprised, he said the number was right on my contact page (and it was) but even though it had been there for years no one had ever called it before, but that was just the type of person Alex was, always reaching out and connecting.</p>\n<p><img src=\"https://atow.files.wordpress.com/2015/09/2007-04-16_2122-18_8683.jpg\" alt=\"\" /></p>\n<p><em>Adam Tow, myself, Barry Abrahamson, Alex King; Photo from <a href=\"http://tow.com/2015/09/28/remembering-alex-king/\">Adam Tow&#8217;s post</a>.</em></p>\n<p>I&#8217;m not sure how to include this next part: I couldn&#8217;t write last night &#8212; I was too tired. After falling&nbsp;asleep I had one of those super vivid dreams that you can&#8217;t tell are dreams. There had been some sort of mix-up on Twitter and Alex was still alive, I&nbsp;visited Colorado with my sister and saw him surrounded by family at a picnic table, all the rooms were taken so they put me on a floor mattress where I slept. Tons of his friends were around and we took pictures together, he was excited about the better front&nbsp;camera on the 6s+. (Alex understood&nbsp;mobile all the way back to the Treo days.) It was all very ordinary and in a group setting, until we decided to walk alongside a small highway, past some grain silos, to meet the group at a bar. The walk was just the two of us and we talked and&nbsp;laughed about the big mix-up and he asked about this post, what was going to be in it. He got most excited and emphatic with the part about him being a developer with great taste, and a clear writer <a href=\"http://www.williamzinsserwriter.com/\">William Zinsser</a> would be proud of, so I like to think that those were two things he was proud of. The overwhelming emotion I remember was joy. Waking up was disconcerting, part of me wants to believe part of Alex&#8217;s spirit was there, where another more logical part thinks my mind was&nbsp;just going through <a href=\"https://en.wikipedia.org/wiki/K%C3%BCbler-Ross_model\">the denial stage of grief</a>. Regardless I know that Alex will stay in the minds of people who knew him for many years to come.</p>\n<p>Code that Alex wrote still runs billions of times a day across millions of websites, and long after that code evolves or gets refactored the ideas and philosophy he embedded in WordPress will continue to be part of who we are. Alex believed so deeply in open source, and was one of the few people from a design background who did. (Every time you see <a href=\"https://en.wikipedia.org/wiki/Share_icon\">the share icon</a> on the web or in Android you should think of him.) I like the idea that part of his work will&nbsp;continue in software for decades to come, but I&#8217;d rather have him here, thinking outside the box and challenging us to do better, to be more obvious, and work harder for our users. He never gave up.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 29 Sep 2015 17:57:43 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"WPTavern: Alex King, Founder of Crowd Favorite Passes Away\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://wptavern.com/?p=48380\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"http://wptavern.com/alex-king-founder-of-crowd-favorite-passes-away\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:8966:\"<a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/AlexKingWithDaughter.jpg\"><img class=\"size-full wp-image-48381\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/AlexKingWithDaughter.jpg?resize=620%2C360\" alt=\"Alex King with his daughter Heather\" /></a>Alex King with his daughter Caitlin\n<p>Alex King, who founded web development agency <a href=\"https://crowdfavorite.com/\">Crowd Favorite,</a> and <a href=\"https://profiles.wordpress.org/alexkingorg/\">author</a> of several WordPress themes and plugins <a href=\"http://tow.com/2015/09/28/remembering-alex-king/\">passed away last night</a> at his home. In January 2013, King was diagnosed with stage four colon cancer. He used his blog to tell the <a href=\"http://alexking.org/blog/thread/cancer\">story of his fight to stay alive</a>.</p>\n<p>On August 24th, King <a href=\"http://alexking.org/blog/2015/08/24/cycle-1-of-new-trial\">finished the first cycle</a> of a new clinical trial that he says went well.</p>\n<blockquote><p>I’m nearly through my first cycle of the new clinical trial and overall I think it’s gone pretty well. I was able to get the 6 pills/day (3 in the morning, 3 in the evening) without too much concern. That said, by the end of the 5 days taking the pills I would basically sleep for the day.</p></blockquote>\n<p>On the same day, he published what would be his <a href=\"http://alexking.org/blog/2015/08/24/rememberances\">final request</a> to the WordPress community. King requested that anyone with memories of him and his career to submit them to his wife.</p>\n<blockquote><p>One of the things my wife and I are trying to do is put together some information about my career that will hopefully give my 6 year-old daughter a better sense of who I was as an adult. She knows me as “dad”, but when she gets older she’ll be curious about who I was to my peers and colleagues.</p></blockquote>\n<p>If you have any memories of King, please honor his request and <a href=\"http://alexking.org/contact\">submit them</a> to his wife.</p>\n<h2>Outpouring of Support</h2>\n<p>As the news of King&#8217;s death spread throughout the community, many shared grief on Twitter while others reflected on his accomplishments in WordPress.</p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">Most <a href=\"https://twitter.com/hashtag/WordPress?src=hash\">#WordPress</a> users will never know how important <a href=\"https://twitter.com/alexkingorg\">@alexkingorg</a> was to our CMS. A great loss to the community. <a href=\"https://t.co/JPtI3gMfE7\">https://t.co/JPtI3gMfE7</a></p>\n<p>&mdash; Name cannot be blank (@mor10) <a href=\"https://twitter.com/mor10/status/648574009097875456\">September 28, 2015</a></p></blockquote>\n<p></p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">alex king (<a href=\"https://twitter.com/alexkingorg\">@alexkingorg</a>) was an incredible asset to <a href=\"https://twitter.com/hashtag/wordpress?src=hash\">#wordpress</a>. he will be missed.</p>\n<p>&mdash; Tom McFarlin (@tommcfarlin) <a href=\"https://twitter.com/tommcfarlin/status/648561299689996288\">September 28, 2015</a></p></blockquote>\n<p></p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">Things <a href=\"https://twitter.com/alexkingorg\">@alexkingorg</a> committed to WordPress: Rss feeds for comments, password protected posts, comments having linkable URLS, &amp; Localization.</p>\n<p>&mdash; Aaron Jorbin (@aaronjorbin) <a href=\"https://twitter.com/aaronjorbin/status/648555278892404736\">September 28, 2015</a></p></blockquote>\n<p></p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">So sad to hear of the death of <a href=\"https://twitter.com/alexkingorg\">@alexkingorg</a>. One of the original WordPress developers. RIP.</p>\n<p>&mdash; Mike Little (@mikelittlezed1) <a href=\"https://twitter.com/mikelittlezed1/status/648639966092902401\">September 28, 2015</a></p></blockquote>\n<p></p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">Very sad to hear about the passing of <a href=\"https://twitter.com/alexkingorg\">@alexkingorg</a> &#8211; smart, analytical, kind, every time I met/talked w/ him.</p>\n<p>&mdash; Cory Miller (@corymiller303) <a href=\"https://twitter.com/corymiller303/status/648590138331656192\">September 28, 2015</a></p></blockquote>\n<p></p>\n<blockquote class=\"twitter-tweet\" width=\"550\"><p lang=\"en\" dir=\"ltr\">One of the earliest <a href=\"https://twitter.com/techstars\">@techstars</a> mentors passed. An original <a href=\"https://twitter.com/WordPress\">@wordpress</a> developer w/ <a href=\"https://twitter.com/photomatt\">@photomatt</a>, <a href=\"https://twitter.com/alexkingorg\">@alexkingorg</a> embodied <a href=\"https://twitter.com/hashtag/givefirst?src=hash\">#givefirst</a> perfectly.</p>\n<p>&mdash; Micah Baldwin (@micah) <a href=\"https://twitter.com/micah/status/648582043161391104\">September 28, 2015</a></p></blockquote>\n<p></p>\n<p>In addition to Twitter, many published their thoughts and memories of King on their site.</p>\n<ul>\n<li><a href=\"http://tow.com/2015/09/28/remembering-alex-king/\">Remembering Alex King</a></li>\n<li><a href=\"http://pressnomics.com/2015/09/alex-king-1975-2015/\">Alex King 1975-2015</a></li>\n<li><a href=\"http://wp.mattwie.be/2015/09/28/rip-alex-king/\">RIP Alex King</a></li>\n<li><a href=\"https://poststatus.com/alex-king/\">Rest in peace, Alex King</a></li>\n<li><a href=\"http://chrislema.com/remembering-alex-king/\">Chris Lema on Remembering Alex King</a></li>\n</ul>\n<h2>King&#8217;s Impact on WordPress Early On</h2>\n<p>King is one of a handful of people who witnessed the transition <a href=\"https://github.com/WordPress/book/blob/master/Content/Part%201/2-b2-cafelog.md\">from b2 to WordPress</a>. He&#8217;s one of the earliest WordPress developers and is largely credited with motivating developers to <a href=\"https://github.com/WordPress/book/blob/master/Content/Part%203/12-themes.md\">build themes</a> using the template engine in WordPress 1.5.</p>\n<blockquote><p>Alex King wrote a <a href=\"http://alexking.org/blog/2004/01/20/wordpress-css-style-switcher\">CSS Style Switcher</a> hack, which came with three CSS stylesheets. Not everyone who had a WordPress blog wanted to create their own stylesheet, and many didn’t know how. Users needed a pool of stylesheets to choose from. To grow the number of stylesheets available, Alex ran a WordPress <a href=\"http://alexking.org/blog/2004/01/25/wordpress-css-style-competition\">CSS Style competition</a>. Prizes, donated by members of the community, were offered for the top three stylesheets; $70, $35, and $10 respectively. &#8211; WordPress History Book</p></blockquote>\n<p>In the first contest, King received 38 submissions with Pink Lillies by Naoko Takano winning first place.</p>\n<a href=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/pink-lillies.png\"><img class=\"size-large wp-image-48383\" src=\"http://i1.wp.com/wptavern.com/wp-content/uploads/2015/09/pink-lillies.png?resize=500%2C300\" alt=\"Pink Lillies Wins First Design Contest\" /></a>Pink Lillies Wins First Design Contest\n<p>Each sylesheet submitted to the contest was <a href=\"http://alexking.org/projects/wordpress/styles\">available to the public</a>. In essence, King&#8217;s website was an early version of the WordPress theme directory. In the <a href=\"http://alexking.org/blog/2005/02/27/wordpress-theme-competition\">second contest</a>, he received over 100 submissions. In total, King hosted 138 themes on his site. He decided not to host the competition again in 2006 due to the sheer amount of work required.</p>\n<h2>Appearances</h2>\n<p>King appeared on several different WordPress podcasts and spoke at a number of WordCamps. Here are links to a few of them.</p>\n<ul>\n<li><a href=\"http://wptavern.com/wpweekly-episode-79-%e2%80%93-alex-king-and-wphelpcenter\">WPWeekly Episode 79 – Alex King And WPHelpCenter</a></li>\n<li><a href=\"https://www.youtube.com/watch?v=6x-WXann_O0\">DradCast &#8211; Episode 037 with Alex King</a></li>\n<li><a href=\"http://www.wpelevation.com/2014/01/episode-15-alex-king/\">WP Elevation Episode #15 – Alex King</a></li>\n<li><a href=\"http://archive.wordpress.org/interviews/2013_04_23_King.html#L53\">Interview from 2013 for the WordPress History book</a></li>\n</ul>\n<p></p>\n<p></p>\n<p></p>\n<h2>My Memorable Experience With Alex King</h2>\n<p>The last time I spoke to King in person was at WordCamp San Francisco 2013. A group of us rode together in a party limo complete with blinking lights inside. I sat across from him and asked a few questions related to his health. I also asked him about the early days of WordPress. King was a soft-spoken man who at times is hard to hear but it turned out to be a great and memorable conversation.</p>\n<p>The WordPress community has lost an inspirational person and a pillar of the WordPress project. My deepest condolences go out to his friends and family. King is survived by his wife Heather and his daughter Caitlin.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 29 Sep 2015 02:42:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jeff Chandler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:10:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Tue, 03 Nov 2015 01:14:20 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:14:\"content-length\";s:6:\"207472\";s:10:\"connection\";s:5:\"close\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:13:\"last-modified\";s:29:\"Tue, 03 Nov 2015 01:00:19 GMT\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:4:\"x-nc\";s:11:\"HIT lax 250\";s:13:\"accept-ranges\";s:5:\"bytes\";}s:5:\"build\";s:14:\"20130911040210\";}','no'),(675,'_transient_timeout_feed_mod_d117b5738fbd35bd8c0391cda1f2b5